INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000000, 2000001, 'Thai-style steamed fish', 'https://www.themealdb.com/images/media/meals/yx8j1i1763484612.jpg', 'https://www.youtube.com/watch?v=KQ-dl8fuBlQ', 'step 1 Nestle the fish fillets side by side on a large square of foil and scatter the ginger, garlic, chilli and lime zest over them. Drizzle the lime juice on top and then scatter the pieces of pak choi around and on top of the fish. Pour the soy sauce over the pak choi and loosely seal the foil to make a package, making sure you leave space at the top for the steam to circulate as the fish cooks. step 2 Steam for 15 minutes. (If you haven’t got a steamer, put the parcel on a heatproof plate over a pan of gently simmering water, cover with a lid and steam.)', 1, NULL, 2, 151, 621, 39.18, 35.38, 93.36, 3.9, 360, 33, 13, 3, 2, 1, 2, '["Thai", "Seafood", "Trout", "Ginger", "Garlic Clove", "Red Chilli", "Lime", "Baby Pak Koi"]', '建议搭配：水果', 0, 0, 2.84, '2025-11-29 11:13:00.945', '青岛', 'HarmonyOS', '2025-11-29 11:13:00.945', '2025-12-04 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000001, 2000003, 'Lamb and Lemon Souvlaki', 'https://www.themealdb.com/images/media/meals/rjhf741585564676.jpg', 'https://www.youtube.com/watch?v=krR4rhjR75Y', 'Pound the garlic with sea salt in a pestle and mortar (or use a small food processor), until the garlic forms a paste. Whisk together the oil, lemon juice, zest, dill and garlic. Mix in the lamb and combine well. Cover and marinate for at least 2 hrs or overnight in the fridge. If you’re going to use bamboo skewers, soak them in cold water. If you’ve prepared the lamb the previous day, take it out of the fridge 30 mins before cooking. Thread the meat onto the soaked or metal skewers. Heat the grill to high or have a hot griddle pan or barbecue ready. Cook the skewers for 2-3 mins on each side, basting with the remaining marinade. Heat the pitta or flatbreads briefly, then stuff with the souvlaki. Add Greek salad (see ''Goes well with'', right) and Tzatziki (below), if you like.', 1, NULL, 3, 163, 508, 28.05, 10.39, 95.43, 4.9, 240, 16, 15, 2, 3, 0, 2, '["Greek", "Lamb", "Garlic", "Sea Salt", "Olive Oil", "Lemon", "Dill", "Lamb Leg"]', '建议搭配：气泡水', 0, 0, 2.16, '2025-12-01 15:13:00.945', '苏州', 'HarmonyOS', '2025-12-01 15:13:00.945', '2025-12-11 12:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000002, 2000000, 'Egg Foo Young', 'https://www.themealdb.com/images/media/meals/47y6ii1765658818.jpg', 'https://www.youtube.com/watch?v=XVTJrkgW304', 'Make the gravy: In a small saucepan, add the beef stock, soy sauce, Shaoxing wine, oyster sauce, and white pepper powder over medium heat. Whisk together and bring to a simmer. Combine the cornstarch and water in a small bowl and whisk to dissolve. Add to the saucepan and whisk until the gravy thickens and coats the back of the spoon, 2 to 3 minutes. Cover the saucepan with a lid and keep it warm on the lowest possible heat. Make the egg foo young batter: In a medium bowl, whisk together the cornstarch and water until dissolved. Add the eggs, salt, and sugar. Whisk until well combined and there are no more egg white clumps. Add the green onion, bean sprouts, and shrimp. Stir until everything is evenly coated. Fry the egg foo young: Add the vegetable oil to a large wok; it should reach abou', 1, NULL, 5, 149, 550, 34.51, 12.13, 24.33, 4.2, 1440, 68, 14, 12, 12, 0, 2, '["Chinese", "Seafood", "Unsalted Beef Stock", "Soy Sauce", "Shaoxing Wine", "Oyster Sauce", "Pepper", "Cornstarch"]', '建议搭配：水果', 0, 0, 0.0, '2025-04-26 06:13:00.945', '南京', 'Windows Web', '2025-04-26 06:13:00.945', '2025-05-04 10:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000003, 2000003, 'Beef Caldereta', 'https://www.themealdb.com/images/media/meals/41cxjh1683207682.jpg', 'https://www.youtube.com/watch?v=yI7hTz0ft5k', '0.	Heat oil in a cooking pot. Saute onion and garlic until onion softens 1.	Add beef. Saute until the outer part turns light brown. 2.	Add soy sauce. Pour tomato sauce and water. Let boil. 3.	Add Knorr Beef Cube. Cover the pressure cooker. Cook for 30 minutes. 4.	Pan-fry carrot and potato until it browns. Set aside. 5.	Add chili pepper, liver spread and peanut butter. Stir. 6.	Add bell peppers, fried potato and carrot. Cover the pot. Continue cooking for 5 to 7 minutes. 7.	Season with salt and ground black pepper. Serve.', 1, NULL, 5, 154, 691, 20.91, 10.12, 67.26, 4.2, 360, 31, 8, 6, 1, 1, 2, '["Filipino", "Beef", "Beef Stock", "Soy Sauce", "Water", "Green Pepper", "Red Pepper"]', '建议搭配：咖啡', 0, 0, 1.95, '2025-04-03 11:13:00.945', '上海', 'Android Tablet', '2025-04-03 11:13:00.945', '2025-04-07 06:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000004, 2000002, 'Algerian Flafla (Bell Pepper Salad)', 'https://www.themealdb.com/images/media/meals/tbj1bs1764118062.jpg', 'https://www.youtube.com/watch?v=JXrS1doDnNg', 'Preheat an oven to 450 degrees F (230 degrees C). Place the whole peppers on aluminum foil. Bake until the skin is spotted black and the peppers are soft, 30 to 45 minutes, turning the peppers once if necessary. Remove peppers from the oven and set aside to cool for 10 minutes. Peel off the skin and remove the stem and seeds. Chop the roasted peppers into half-inch pieces. Heat the olive oil in a skillet over medium heat. Stir in the onion and cook, stirring frequently, until the onion has softened and turned translucent, about 5 minutes. Add the garlic, salt, and pepper; stir in the chopped peppers and tomato. Cook over medium heat, stirring occasionally, until the tomato is soft and the mixture is well incorporated, about 5 minutes.', 1, NULL, 3, 118, 552, 43.44, 28.27, 77.3, 4.6, 120, 8, 0, 2, 1, 0, 2, '["Algerian", "Vegetarian", "Green Pepper", "Olive Oil", "Red Onions", "Garlic", "Salt", "Pepper"]', '建议搭配：热汤', 0, 0, 6.12, '2025-05-14 02:13:00.945', '北京', 'iPhone 15', '2025-05-14 02:13:00.945', '2025-05-16 21:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000005, 2000004, 'Yaki Udon', 'https://www.themealdb.com/images/media/meals/wrustq1511475474.jpg', 'https://www.youtube.com/watch?v=5Iy0MCowSvA', 'Boil some water in a large saucepan. Add 250ml cold water and the udon noodles. (As they are so thick, adding cold water helps them to cook a little bit slower so the middle cooks through). If using frozen or fresh noodles, cook for 2 mins or until al dente; dried will take longer, about 5-6 mins. Drain and leave in the colander. Heat 1 tbsp of the oil, add the onion and cabbage and sauté for 5 mins until softened. Add the mushrooms and some spring onions, and sauté for 1 more min. Pour in the remaining sesame oil and the noodles. If using cold noodles, let them heat through before adding the ingredients for the sauce – otherwise tip in straight away and keep stir-frying until sticky and piping hot. Sprinkle with the remaining spring onions.', 1, NULL, 3, 24, 254, 26.4, 35.33, 57.14, 3.5, 840, 37, 2, 7, 2, 0, 2, '["LowCalorie", "Japanese", "Vegetarian", "Udon Noodles", "Sesame Seed Oil", "Onion", "Cabbage", "Shiitake Mushrooms", "Spring Onions"]', '建议搭配：气泡水', 0, 0, 1.5, '2025-09-26 21:13:00.945', '青岛', 'iPad', '2025-09-26 21:13:00.945', '2025-09-30 09:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000006, 2000003, 'Rock Cakes', 'https://www.themealdb.com/images/media/meals/tqrrsq1511723764.jpg', 'https://www.youtube.com/watch?v=tY3taZO3Aro', 'Preheat oven to 180C/350F/Gas 4 and line a baking tray with baking parchment. Mix the flour, sugar and baking powder in a bowl and rub in the cubed butter until the mixture looks like breadcrumbs, then mix in the dried fruit. In a clean bowl, beat the egg and milk together with the vanilla extract. Add the egg mixture to the dry ingredients and stir with a spoon until the mixture just comes together as a thick, lumpy dough. Add a teaspoon more milk if you really need it to make the mixture stick together. Place golfball-sized spoons of the mixture onto the prepared baking tray. Leave space between them as they will flatten and spread out to double their size during baking. Bake for 15-20 minutes, until golden-brown. Remove from the oven, allow to cool for a couple of minutes then turn them', 2, NULL, 3, 42, 324, 0.0, 28.59, 43.25, 3.5, 3840, 325, 104, 25, 18, 0, 2, '["Baking", "Cake", "British", "Dessert", "Self-raising Flour", "Caster Sugar", "Baking Powder", "Butter", "Dried Fruit", "Eggs"]', '建议搭配：气泡水', 1, 0, 7.61, '2025-07-16 12:13:00.945', '武汉', 'HarmonyOS', '2025-07-16 12:13:00.945', '2025-07-23 18:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000007, 2000004, 'Tajine de Poulet aux Carottes et Patates Douces (Chicken and Sweet Potato Tagine)', 'https://www.themealdb.com/images/media/meals/d8bfyg1764117503.jpg', 'https://www.youtube.com/watch?v=thf-JDXoTVg', 'Combine onions, celery, cilantro, and parsley in a large pot. Stir in turmeric, cumin, paprika, ginger, cayenne pepper, salt, and pepper. Place chicken thighs on top. Drizzle olive oil over chicken. Cover and simmer over low heat until chicken is tender, about 40 minutes. Place raisins in a small bowl and cover with hot water; let soak for 10 minutes. Drain. Preheat oven to 400 degrees F (200 degrees C). Transfer chicken mixture into an oven-safe tagine or casserole dish. Add sweet potato and carrots. Cover with lid or aluminum foil. Bake in the preheated oven until sweet potato is soft, about 40 minutes. Add drained raisins and prunes. Continue baking, covered, until raisins and prunes are heated through, about 10 minutes.', 1, NULL, 4, 212, 660, 45.55, 19.2, 34.15, 3.9, 360, 9, 20, 2, 1, 0, 2, '["Algerian", "Chicken", "Onion", "Celery", "Cilantro", "Parsley", "Turmeric", "Ground Cumin"]', '建议搭配：气泡水', 0, 0, 12.94, '2025-05-12 04:13:00.945', '上海', 'iPhone 15', '2025-05-12 04:13:00.945', '2025-05-14 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000008, 2000001, 'Beef Lo Mein', 'https://www.themealdb.com/images/media/meals/1529444830.jpg', 'https://www.youtube.com/watch?v=ZT9LSsNXXe0', 'STEP 1 - MARINATING THE BEEF In a bowl, add the beef, salt, 1 pinch white pepper, 1 Teaspoon sesame seed oil, 1/2 egg, corn starch,1 Tablespoon of oil and mix together. STEP 2 - BOILING THE THE NOODLES In a 6 qt pot add your noodles to boiling water until the noodles are submerged and boil on high heat for 10 seconds. After your noodles is done boiling strain and cool with cold water. STEP 3 - STIR FRY Add 2 Tablespoons of oil, beef and cook on high heat untill beef is medium cooked. Set the cooked beef aside In a wok add 2 Tablespoon of oil, onions, minced garlic, minced ginger, bean sprouts, mushrooms, peapods and 1.5 cups of water or until the vegetables are submerged in water. Add the noodles to wok To make the sauce, add oyster sauce, 1 pinch white pepper, 1 teaspoon sesame seed oil, ', 1, NULL, 4, 113, 335, 14.3, 3.27, 77.35, 3.9, 240, 19, 9, 2, 1, 0, 2, '["Chinese", "Beef", "Salt", "Pepper", "Sesame Seed Oil", "Egg", "Starch"]', '建议搭配：水果', 0, 0, 6.54, '2025-04-24 14:13:00.945', '南京', 'Android Tablet', '2025-04-24 14:13:00.945', '2025-05-01 06:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000009, 2000000, 'Spicy Thai prawn noodles', 'https://www.themealdb.com/images/media/meals/568t931763584227.jpg', '', 'step 1 Cook the noodles following the pack instructions, drain and set aside for later. Heat the oil in a large frying pan and pour in the beaten egg. Swirl around the pan to make a thin omelette, cook for 1-2 mins, then flip over and cook the other side for 1 min. Tip out and slice into thin strips. step 2 Add the chilli and ginger to the pan, fry for 1-2 mins then tip in the noodles, prawns and egg. Splash in the soy sauce and stir-fry for 1 min more. Throw in the chopped herbs and pour over the lime juice and zest, then sprinkle over the chopped peanuts and serve.', 1, NULL, 3, 73, 229, 37.63, 8.96, 48.33, 3.8, 120, 5, 3, 0, 0, 0, 2, '["Thai", "Seafood", "Rice Noodles", "Sesame Seed Oil", "Egg", "Red Chilli", "Ginger", "Prawns"]', '建议搭配：咖啡', 0, 0, 8.34, '2025-12-12 10:13:00.945', '北京', 'Android Tablet', '2025-12-12 10:13:00.945', '2025-12-20 01:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000010, 2000004, 'Ayam Percik', 'https://www.themealdb.com/images/media/meals/020z181619788503.jpg', 'https://www.youtube.com/watch?v=9ytR28QK6I8', 'In a blender, add the ingredients for the spice paste and blend until smooth. Over medium heat, pour the spice paste in a skillet or pan and fry for 10 minutes until fragrant. Add water or oil 1 tablespoon at a time if the paste becomes too dry. Don''t burn the paste. Lower the fire slightly if needed. Add the cloves, cardamom, tamarind pulp, coconut milk, water, sugar and salt. Turn the heat up and bring the mixture to boil. Turn the heat to medium low and simmer for 10 minutes. Stir occasionally. It will reduce slightly. This is the marinade/sauce, so taste and adjust seasoning if necessary. Don''t worry if it''s slightly bitter. It will go away when roasting. When the marinade/sauce has cooled, pour everything over the chicken and marinate overnight to two days. Preheat the oven to 425 F. ', 1, NULL, 5, 166, 260, 37.55, 17.73, 15.08, 3.2, 120, 13, 5, 0, 0, 0, 2, '["Malaysian", "Chicken", "Chicken Thighs", "Challots", "Ginger", "Garlic Clove", "Cayenne Pepper", "Turmeric"]', '建议搭配：气泡水', 0, 0, 7.44, '2025-09-10 22:13:00.945', '上海', 'iPad', '2025-09-10 22:13:00.945', '2025-09-15 11:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000011, 2000001, 'Honey Teriyaki Salmon', 'https://www.themealdb.com/images/media/meals/xxyupu1468262513.jpg', 'https://www.youtube.com/watch?v=4MpYuaJsvRw', 'Mix all the ingredients in the Honey Teriyaki Glaze together. Whisk to blend well. Combine the salmon and the Glaze together. Heat up a skillet on medium-low heat. Add the oil, Pan-fry the salmon on both sides until it’s completely cooked inside and the glaze thickens. Garnish with sesame and serve immediately.', 1, NULL, 2, 78, 589, 0.0, 25.87, 85.2, 5.0, 120, 4, 2, 1, 1, 0, 2, '["Fish", "Breakfast", "DateNight", "Japanese", "Seafood", "Salmon", "Olive oil", "Soy Sauce", "Sake", "Sesame Seed"]', '建议搭配：气泡水', 0, 0, 4.19, '2025-11-25 13:13:00.945', '武汉', 'Windows Web', '2025-11-25 13:13:00.945', '2025-11-26 20:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000012, 2000004, 'Blini Pancakes', 'https://www.themealdb.com/images/media/meals/0206h11699013358.jpg', 'https://www.youtube.com/watch?v=GsB8ZI5vREA', 'In a large bowl, whisk together 1/2 cup buckwheat flour, 2/3 cup all-purpose flour, 1/2 teaspoon salt, and 1 teaspoon yeast. Make a well in the center and pour in 1 cup warm milk, whisking until the batter is smooth. Cover the bowl and let the batter rise until doubled, about 1 hour. Enrich and Rest the Batter Stir 2 tablespoons melted butter and 1 egg yolk into the batter. In a separate bowl, whisk 1 egg white until stiff, but not dry. Fold the whisked egg white into the batter. Cover the bowl and let the batter stand 20 minutes. Pan-Fry the Blini Heat butter in a large nonstick skillet over medium heat. Drop quarter-sized dollops of batter into the pan, being careful not to overcrowd the pan. Cook for about 1 minute or until bubbles form. Turn and cook for about 30 additional seconds. Re', 1, NULL, 4, 74, 711, 28.74, 5.71, 108.33, 4.3, 120, 7, 1, 0, 0, 0, 2, '["Pancake", "Russian", "Side", "Buckwheat", "Flour", "Salt", "Yeast", "Milk", "Butter"]', '建议搭配：水果', 0, 0, 0.0, '2025-09-21 06:13:00.945', '上海', 'iPad', '2025-09-21 06:13:00.945', '2025-09-26 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000013, 2000001, 'kabse', 'https://www.themealdb.com/images/media/meals/utqnjv1763598650.jpg', 'https://www.youtube.com/watch?v=lrcUixJEPK0', '1 Caramelize the chicken with olive oil then add a maggi cube and boil it for around 30 minutes. 2 In another pot, add all the veggies and caramelize them till they are soft. 3 Once everything is done, add the rice, raisins & spices to the veggies and add 2 and a half cups of water for the rice to cook. 4 Once the rice is done put everything in the oven.', 1, NULL, 1, 65, 936, 5.91, 4.13, 35.5, 3.6, 240, 12, 0, 0, 0, 1, 2, '["Saudi Arabian", "Chicken", "Rice", "Green Pepper", "Red Pepper", "Mushrooms", "Sweetcorn"]', '建议搭配：气泡水', 0, 0, 4.19, '2025-08-21 15:13:00.945', '杭州', 'Android Tablet', '2025-08-21 15:13:00.945', '2025-08-29 15:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000014, 2000004, 'Roast aubergine with goat''s cheese & toasted flatbread', 'https://www.themealdb.com/images/media/meals/iydbwy1763816111.jpg', '', 'step 1 Heat oven to 200C/180C fan/gas 6. Brush the aubergine slices with 1 tbsp of the oil, then season. Arrange on a baking tray or sheet and roast for 20 mins until browned, popping the tomatoes on the tray for the final 5 mins. Tear the flatbread into pieces and place on a separate baking sheet. Brown in the oven for 8 mins, or until crisp, then remove. step 2 For the dressing, in a small bowl, mix the vinegar, mint, chopped shallots, chilli, remaining oil and some salt and pepper. step 3 Scatter the aubergine slices, tomatoes, sliced shallot and crisp flatbread into a serving bowl. Pour over the dressing, sprinkle with the goat’s cheese and scatter over a little rocket.', 1, NULL, 3, 216, 314, 25.91, 0.0, 63.44, 4.7, 120, 10, 0, 0, 0, 0, 2, '["Turkish", "Vegetarian", "Aubergine", "Extra Virgin Olive Oil", "Cherry Tomatoes", "Pita Bread", "Balsamic Vinegar", "Mint"]', '建议搭配：咖啡', 0, 0, 0.0, '2025-04-16 18:13:00.945', '苏州', 'Mac Safari', '2025-04-16 18:13:00.945', '2025-04-17 18:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000015, 2000004, 'Jamaican Beef Patties', 'https://www.themealdb.com/images/media/meals/wsqqsw1515364068.jpg', 'https://www.youtube.com/watch?v=ypQjoiZiTac', 'Make the Pastry Dough To a large bowl, add flour, 1 teaspoon salt, and turmeric and mix thoroughly. Rub shortening into flour until there are small pieces of shortening completely covered with flour. Pour in 1/2 cup of the ice water and mix with your hands to bring the dough together. Keep adding ice water 2 to 3 tablespoons at a time until the mixture forms a dough. At this stage, you can cut the dough into 2 large pieces, wrap in plastic and refrigerate for 30 minutes before using it. Alternatively, cut the dough into 10 to 12 equal pieces, place on a platter or baking sheet, cover securely with plastic wrap and let chill for 30 minutes while you make the filling. Make the Filling Add ground beef to a large bowl. Sprinkle in allspice and black pepper. Mix together and set aside. Heat oil', 1, NULL, 5, 118, 372, 32.82, 0.0, 10.54, 4.2, 120, 7, 3, 1, 0, 0, 2, '["Snack", "Spicy", "Jamaican", "Beef", "Plain Flour", "Salt", "Curry Powder", "Butter", "Water", "Minced Beef"]', '建议搭配：水果', 0, 0, 5.17, '2025-09-25 03:13:00.945', '深圳', 'HarmonyOS', '2025-09-25 03:13:00.945', '2025-09-29 03:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000016, 2000003, 'Eggplant Adobo', 'https://www.themealdb.com/images/media/meals/y7h0lq1683208991.jpg', 'https://www.youtube.com/watch?v=pKXACYjwMns', '1.	Slice 1 lb. small Japanese or Italian eggplant (about 3) into quarters lengthwise, then cut crosswise into 2"-wide pieces. Place in a medium bowl. Add 1 Tbsp. sugar, 1 tsp. Diamond Crystal or ½ tsp. Morton kosher salt, and ½ tsp. freshly ground black pepper. Toss to evenly coat eggplant and let sit at room temperature at least 20 minutes and up to 2 hours. 2.	Peel and thinly slice 8 garlic cloves. Add 3 Tbsp. vegetable oil and half of garlic to a medium Dutch oven or other heavy pot. Cook over medium-high heat, stirring constantly with a wooden spoon, until light golden and crisp, about 5 minutes. Using a slotted spoon, transfer garlic chips to a plate; season lightly with salt. 3. Place 4 oz. ground pork in same pot and break up into small pieces with wooden spoon. Season with ¼ tsp. D', 1, NULL, 5, 125, 684, 20.36, 18.96, 89.7, 3.7, 240, 8, 7, 3, 0, 0, 2, '["Filipino", "Vegetarian", "Egg Plants", "Sugar", "Salt", "Pepper", "Garlic", "Olive Oil"]', '建议搭配：咖啡', 0, 0, 13.1, '2025-05-09 00:13:00.945', '北京', 'Android Tablet', '2025-05-09 00:13:00.945', '2025-05-09 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000017, 2000003, 'Rye bread', 'https://www.themealdb.com/images/media/meals/lmc6r51764365554.jpg', 'https://www.youtube.com/watch?v=bP7m7xx0GpM', 'step 1 Tip the flours, yeast and salt into a bowl. In a jug, mix the honey with 250ml warm water, pour the liquid into the bowl and mix to form a dough. Rye flour can be quite dry and absorbs lots of water, if the dough looks too dry add more warm water until you have a soft dough Tip out onto your work surface and knead for 10 mins until smooth. Rye contains less gluten than white flour so the dough will not feel as springy as a conventional white loaf. step 2 Place the dough in a well oiled bowl, cover with cling film and leave to rise in a warm place for 1-2 hrs, or until roughly doubled in size. Dust a 2lb/900g loaf tin with flour. step 3 Tip the dough back onto your work surface and knead briefly to knock out any air bubbles. If using caraway seeds work these in to the dough. Shape in', 1, NULL, 5, 240, 458, 42.4, 0.0, 51.63, 4.6, 120, 0, 2, 1, 0, 0, 2, '["Polish", "Side", "Rye", "Strong white bread flour", "Yeast", "Salt", "Honey", "Caraway Seed"]', '建议搭配：清爽沙拉', 0, 0, 7.37, '2025-05-19 00:13:00.945', '广州', 'Windows Web', '2025-05-19 00:13:00.945', '2025-05-23 22:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000018, 2000002, 'Anzac biscuits', 'https://www.themealdb.com/images/media/meals/q47rkb1762324620.jpg', 'https://www.youtube.com/watch?v=1nAVbfQVWRQ', 'step 1 Heat oven to 180C/fan 160C/gas 4. Put the oats, coconut, flour and sugar in a bowl. Melt the butter in a small pan and stir in the golden syrup. Add the bicarbonate of soda to 2 tbsp boiling water, then stir into the golden syrup and butter mixture. step 2 Make a well in the middle of the dry ingredients and pour in the butter and golden syrup mixture. Stir gently to incorporate the dry ingredients. step 3 Put dessertspoonfuls of the mixture on to buttered baking sheets, about 2.5cm/1in apart to allow room for spreading. Bake in batches for 8-10 mins until golden. Transfer to a wire rack to cool.', 2, NULL, 4, 106, 547, 43.81, 36.74, 104.13, 5.0, 120, 4, 2, 0, 0, 0, 2, '["Australian", "Dessert", "Porridge oats", "Desiccated Coconut", "Plain Flour", "Caster Sugar", "Butter", "Golden Syrup"]', '建议搭配：清爽沙拉', 0, 1, 10.14, '2025-09-06 09:13:00.945', '深圳', 'Mac Safari', '2025-09-06 09:13:00.945', '2025-09-16 06:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000019, 2000004, 'Shakshuka Feta Cheese', 'https://www.themealdb.com/images/media/meals/wpkfin1763597958.jpg', 'https://www.youtube.com/watch?v=xaBo3BxKzp8', '1 In a pan heat the oil medium to high heat, with a tablespoon of olive oil 2 Add the chopped vegetables as onions, garlic, celery and red pepper. Stir all together for 5 mins. 3 Add the cumin powder and salt and pepper and the tomato sauce and let it cook for another 7 mins. 4 Add the eggs, cover and leave to coo for 8 mins. Add the fresh spinach and feta cheese at the end. 5 Serve with fresh bread.', 1, NULL, 2, 83, 156, 0.0, 1.94, 94.0, 4.2, 240, 2, 2, 2, 2, 0, 2, '["Cheesy", "Saudi Arabian", "Miscellaneous", "Egg", "Tomato Sauce", "Olive Oil", "Shallots", "Celery", "Garlic"]', '建议搭配：气泡水', 0, 0, 6.61, '2026-02-10 09:13:00.945', '武汉', 'Android 14 Pixel', '2026-02-10 09:13:00.945', '2026-02-16 23:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000020, 2000003, 'Shawarma bread', 'https://www.themealdb.com/images/media/meals/i8l2fu1763742525.jpg', 'https://www.youtube.com/watch?v=ndkTbgsTCeI', '1 Sieve flour and add baking powder,salt,sugar,oil nd mix together 2 Add water nd knead the dough for like 10mins 3 Cover the mixture and allow it to rise 4 After it rised transfer it to a work surface and form a round (you can use a plate or pot''s lid) 5 Heat ur pan and put it 6 It''ll start puffing then you turn it 7 And lastly put it in in a warm place, then you''ll see it has pocket', 1, NULL, 2, 16, 630, 36.96, 33.64, 37.92, 4.1, 3960, 151, 152, 31, 1, 17, 2, '["Saudi Arabian", "Side", "Flour", "Salt", "Sugar", "Baking Powder", "Oil", "Water"]', '建议搭配：水果', 0, 0, 0.0, '2025-07-08 03:13:00.945', '北京', 'Android 14 Pixel', '2025-07-08 03:13:00.945', '2025-07-09 14:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000021, 2000003, 'Chorizo & tomato salad', 'https://www.themealdb.com/images/media/meals/6cskio1763338156.jpg', 'https://www.youtube.com/watch?v=RFlENguMJNA', 'step 1 Put the tomatoes in a bowl with the onion and thyme. Season, then drizzle with the vinegar and oil. Let the flavours mingle while you cook the chorizo. step 2 In a hot, dry pan, fry the chorizo slices until browned on both sides. Serve the tomatoes with the fried chorizo, drizzled with a little oil from the pan.', 1, NULL, 2, 88, 419, 28.89, 38.93, 27.85, 4.5, 1200, 120, 80, 21, 16, 2, 2, '["Spanish", "Pork", "Beef tomatoes", "Red Onions", "Thyme", "Sherry vinegar", "Extra Virgin Olive Oil", "Chorizo"]', '建议搭配：水果', 0, 0, 4.67, '2025-10-30 09:13:00.945', '青岛', 'iPhone 15', '2025-10-30 09:13:00.945', '2025-11-02 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000022, 2000004, 'Hodge Podge', 'https://www.themealdb.com/images/media/meals/xihv0c1764447887.jpg', '', 'First, cook your vegetables. Bring a large pot of salted water to boil. Par-cook carrots and potatoes for five minutes until carrots and potatoes are fork tender, then blanch the peas and beans for about a minute in the same pot. Strain vegetables and set aside. In a heavy-bottomed pot or Dutch oven, melt butter over medium heat, add vegetables, and cook to warm through. Add milk and cream and bring the soup to a boil. Turn the heat down to low and season with salt and pepper. Add dill and chives and let simmer for at least 10 minutes. Serve warm.', 1, NULL, 3, 170, 750, 28.52, 24.85, 46.42, 3.7, 1080, 45, 66, 6, 0, 0, 2, '["Canadian", "Vegetarian", "New Potatoes", "Carrots", "Green Beans", "Peas", "Dill", "Chives"]', '建议搭配：清爽沙拉', 0, 0, 7.85, '2025-07-29 10:13:00.945', '杭州', 'Mac Safari', '2025-07-29 10:13:00.945', '2025-08-01 19:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000023, 2000000, 'Spaghetti with Spanish flavours', 'https://www.themealdb.com/images/media/meals/vpcqn01763335688.jpg', 'https://www.youtube.com/watch?v=BukrisTBv00', 'step 1 Put a pan of water on over a high heat to boil. Meanwhile, snip the chorizo into strips with scissors, and chop the parsley and peppers (check for stray seeds first). step 2 When the water is boiling briskly, add the spaghetti with a good measure of salt, stir and return to the boil. Cook for 3 minutes. step 3 In a large frying pan, heat the oil, add the chorizo and peppers and plenty of black pepper. Cook for a minute or so, until heated through and the juices are stained red from the paprika in the chorizo. Scoop half a mugful of pasta water from the pan, drain the remainder and tip the spaghetti into the frying pan. step 4 Add the parsley and parmesan, toss well and splash in the pasta water, to moisten. Hand round extra parmesan at the table.', 1, NULL, 4, 50, 373, 26.05, 31.55, 16.53, 4.1, 120, 4, 1, 0, 1, 0, 2, '["Spanish", "Pork", "Chorizo", "Spaghetti", "Parsley", "Red Pepper", "Olive Oil", "Parmesan Cheese"]', '建议搭配：气泡水', 0, 0, 0.35, '2025-04-15 04:13:00.945', '深圳', 'Android Tablet', '2025-04-15 04:13:00.945', '2025-04-21 16:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000024, 2000004, 'Chinese Tomato Egg Stir Fry', 'https://www.themealdb.com/images/media/meals/rwvw8q1765660071.jpg', 'https://www.youtube.com/watch?v=Wn8ox93Qhus', 'You can use chicken broth in place of the chicken bouillon powder. Add 1/4 cup of broth followed by 2 teaspoons of cornstarch dissolved in 1 tablespoPrepare the tomatoes: Slice the tomatoes in half. Remove the tough stem from each half that connects to the vine. Cut each half into equal thirds (you’ll get 6 slices from each tomato). Make the soft scrambled eggs: In a cold, 8 to 10-inch nonstick skillet, add the vegetable oil and beaten eggs. Turn the heat to medium. Once a thin layer of eggs is just beginning to cook on the bottom, push the eggs in one direction to create layers of scrambled eggs. Cook, gently stirring the whole time, until the scramble eggs are mostly set but still slightly wet and shiny, 2 to 5 minutes. Remove the eggs to a plate and, if needed, wipe out the pan. Stir-fr', 1, NULL, 5, 240, 723, 13.53, 20.52, 91.35, 4.6, 120, 11, 2, 1, 1, 0, 2, '["Chinese", "Vegetarian", "Plum Tomatoes", "Vegetable Oil", "Eggs", "Sesame Seed Oil", "Chicken Bouillon Powder", "Sugar"]', '建议搭配：咖啡', 0, 0, 9.78, '2025-06-18 19:13:00.945', '武汉', 'Windows Web', '2025-06-18 19:13:00.945', '2025-06-19 19:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000025, 2000002, 'Vegan Chocolate Cake', 'https://www.themealdb.com/images/media/meals/qxutws1486978099.jpg', 'https://www.youtube.com/watch?v=C3pAgB7pync', 'Simply mix all dry ingredients with wet ingredients and blend altogether. Bake for 45 min on 180 degrees. Decorate with some melted vegan chocolate', 1, NULL, 1, 25, 294, 9.33, 40.45, 68.33, 4.1, 2040, 208, 59, 32, 25, 9, 2, '["Vegan", "Chocolate", "Cake", "American", "Self-raising Flour", "coco sugar", "cacao", "baking powder", "flax eggs", "almond milk"]', '建议搭配：咖啡', 0, 0, 3.57, '2026-01-31 08:13:00.945', '杭州', 'Mac Safari', '2026-01-31 08:13:00.945', '2026-01-31 15:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000026, 2000001, 'Cumberland Pie', 'https://www.themealdb.com/images/media/meals/pvfkz61761595976.jpg', 'https://www.youtube.com/watch?v=r1lnsOTNjws', 'step 1 Heat oven to 160C/140C fan/gas 3. Soften the celery, onion, carrots, bay and 1 thyme sprig in a casserole with 1 tbsp oil and the butter for 10 mins. Stir in the flour, followed by the purée, Worcestershire sauce and stock cubes. step 2 Gradually stir in 600ml hot water, then tip in the beef and bring to a gentle simmer. Cover and cook in the oven for 2 hrs 30 mins, then uncover and cook for 30 mins -1 hr more until the meat is really tender and sauce thickened. step 3 Meanwhile, cook potatoes in a pan of boiling water until they’re not done but about ¾ of the way there. step 4 Transfer meat to a baking dish. Slice spuds into 1cm thick rounds and gently toss with seasoning, the remaining oil and thyme leaves. Layer on the beef, scattering with the cheese as you layer. You can cover ', 1, NULL, 5, 107, 433, 44.8, 12.71, 84.65, 4.8, 120, 5, 3, 1, 0, 0, 2, '["British", "Beef", "Celery", "Onion", "Carrots", "Bay Leaves", "Thyme", "Vegetable Oil"]', '建议搭配：热汤', 0, 0, 12.55, '2025-08-03 20:13:00.945', '南京', 'iPad', '2025-08-03 20:13:00.945', '2025-08-11 14:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000027, 2000003, 'Jamaican Curry Shrimp Recipe', 'https://www.themealdb.com/images/media/meals/n7h5zs1765318909.jpg', 'https://www.youtube.com/watch?v=Lnaj4duQ7hs', 'Season shrimp with 1 Tablespoon of curry powder and all-purpose seasoning and set aside for about 10 minutes while you prepare the other ingredients like chopping your onions, peppers, and garlic. Heat 2 Tablespoons of olive oil in a large skillet over medium heat. Add sliced yellow onion, red bell pepper, green bell pepper, scotch bonnet pepper, if using, and chopped garlic and stir for 5 minutes, until peppers are slightly softened. Add 1.5 Tablespoons of curry powder to the skillet and stir for an additional minute. Then add coconut milk, seasoned shrimp, ketchup, and thyme, making sure the shrimp is covered in the sauce. Allow the sauce to come to a simmer and continue to cook over medium heat, stirring occasionally and flipping the shrimp halfway, until the shrimp is fully cooked on b', 1, NULL, 3, 77, 598, 20.58, 0.0, 42.28, 4.4, 120, 12, 7, 0, 1, 0, 2, '["Jamaican", "Seafood", "Jumbo Shrimp", "Jamaican Curry Powder", "All-purpose Seasoning", "Olive Oil", "Onion", "Red Pepper"]', '建议搭配：气泡水', 0, 0, 17.32, '2025-07-28 11:13:00.945', '上海', 'Android 14 Pixel', '2025-07-28 11:13:00.945', '2025-07-29 10:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000028, 2000001, 'Grilled Portuguese sardines', 'https://www.themealdb.com/images/media/meals/lpd4wy1614347943.jpg', 'https://www.youtube.com/watch?v=JYtMjKa6cdY', 'STEP 1 Put all of the ingredients, except the sardines, into a bowl and mix together with some seasoning. Pour into a baking dish, add the sardines and toss really well. Cover and chill for a few hours. STEP 2 Heat a BBQ or griddle pan until hot. Cook the sardines for 4-5 minutes on each side or until really caramelised and charred. Put onto a serving plate, drizzle with oil, sprinkle with a little more paprika and squeeze over the lemon wedges.', 1, NULL, 3, 94, 689, 4.26, 23.39, 57.11, 4.0, 120, 2, 5, 1, 0, 0, 2, '["Portuguese", "Seafood", "Sardines", "Olive Oil", "Garlic", "Paprika", "Lemon", "Rosemary"]', '建议搭配：热汤', 0, 0, 9.94, '2025-07-05 18:13:00.945', '南京', 'HarmonyOS', '2025-07-05 18:13:00.945', '2025-07-13 10:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000029, 2000001, 'Jamaican Steamed Cabbage', 'https://www.themealdb.com/images/media/meals/paejva1765321314.jpg', 'https://www.youtube.com/watch?v=amEkrC9rzgM', 'Add all the ingredients to a large pan over medium heat and cover with a lid. Cook on medium heat for 10 minutes, stirring occasionally. After 10 minutes, reduce the heat to low and continue to cook for an additional 5 minutes, until the cabbage is soft and tender. Remove from the heat and remove the stalks of thyme before serving.', 1, NULL, 1, 40, 355, 39.4, 19.94, 61.76, 5.0, 360, 3, 1, 2, 0, 0, 2, '["Jamaican", "Side", "Cabbage", "Carrots", "Plum Tomatoes", "Onion", "Garlic", "Spring Onions"]', '建议搭配：咖啡', 0, 0, 13.52, '2025-12-25 22:13:00.945', '广州', 'Mac Safari', '2025-12-25 22:13:00.945', '2025-12-31 20:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000030, 2000002, 'Suksessterte (Norwegian almond “success cake”)', 'https://www.themealdb.com/images/media/meals/de83k51763075604.jpg', 'https://www.youtube.com/watch?v=LgIQXxkOrMM', 'Almond base ▢ Preheat oven to 345°F (175°C) and grease cake form (I use a 27 cm spring form) – you can line the bottom with baking paper if you like. ▢ Grind almonds in an almond grinder or food processor. I like to keep them a bit coarse. ▢ Gently whisk the eggs and sugar together until combined (no longer). Stir in the ground almonds, flour, and baking powder. ▢ Pour batter into cake form and bake for about 45 – 50 minutes, monitoring to make sure the top doesn''t burn. Yellow egg cream ▢ Add egg yolks, heavy cream, sugar, and vanilla to a saucepan. Heat over low/medium heat while stirring constantly until the mixture thickens – about 15 minutes. Turn up the heat if the mixture doesn''t thicken, but be careful not to boil. ▢ Let the mixture cool to room temperature and then add the butter.', 2, NULL, 4, 86, 651, 14.81, 30.37, 60.19, 4.4, 120, 9, 5, 0, 0, 0, 2, '["Norwegian", "Dessert", "Almonds", "Egg", "Granulated Sugar", "Flour", "Baking Powder", "Egg Yolks"]', '建议搭配：咖啡', 0, 0, 10.74, '2026-02-01 04:13:00.945', '重庆', 'Windows Web', '2026-02-01 04:13:00.945', '2026-02-03 03:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000031, 2000000, 'Sukuma Wiki', 'https://www.themealdb.com/images/media/meals/60o82j1762341177.jpg', 'https://www.youtube.com/watch?v=02hHtPDAxOs', 'Heat the 2 tablespoons of oil in a large skillet or pot over medium heat until shimmering. Add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes. Add the shredded kale to the onions and mix well. Turn the heat to medium-low, cover and cook for 5 minutes. After 5 minutes, remove the lid, add salt to taste, and stir in the cream. Continue cooking for another 5 minutes, uncovered, stirring occasionally. The cream will thicken slightly, making for a deliciously rich creamed kale and onions. Yumm! Serve it up with your favorite Kenyan stew, and a side of ugali!', 1, NULL, 3, 111, 556, 7.53, 7.09, 85.87, 4.1, 120, 2, 2, 1, 1, 0, 2, '["Kenyan", "Vegetarian", "Oil", "Red Onions", "Kale", "Salt", "Double Cream"]', '建议搭配：热汤', 0, 0, 9.13, '2025-06-22 10:13:00.945', '武汉', 'Android Tablet', '2025-06-22 10:13:00.945', '2025-06-25 22:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000032, 2000001, 'Blackberry Fool', 'https://www.themealdb.com/images/media/meals/rpvptu1511641092.jpg', 'https://www.youtube.com/watch?v=kniRGjDLFrQ', 'For the biscuits, preheat the oven to 200C/180C (fan)/Gas 6 and line two large baking trays with baking parchment. Scatter the nuts over a baking tray and roast in the oven for 6-8 minutes, or until golden-brown. Watch them carefully so that they don’t have a chance to burn. Remove from the oven, tip onto a board and leave to cool. Put the butter and sugar in a large bowl and beat with a wooden spoon until light and creamy. Roughly chop the cooled nuts and add to the creamed butter and sugar, along with the lemon zest, flour and baking powder. Stir well until the mixture comes together and forms a ball – you may need to use your hands. Divide the biscuit dough into 24 even pieces and roll into small balls. Place the balls the prepared baking trays, spaced well apart to allow for spreading.', 2, NULL, 5, 168, 292, 39.76, 18.11, 43.76, 4.7, 480, 31, 11, 2, 4, 1, 2, '["Desert", "Summer", "Fruity", "Dairy", "British", "Dessert", "Hazlenuts", "Butter", "Caster Sugar", "Lemon", "Plain Flour", "Baking Powder"]', '建议搭配：咖啡', 0, 0, 3.07, '2025-12-26 08:13:00.945', '北京', 'Android 14 Pixel', '2025-12-26 08:13:00.945', '2026-01-03 15:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000033, 2000004, 'Thai pork & peanut curry', 'https://www.themealdb.com/images/media/meals/snmtd61763426568.jpg', 'https://www.youtube.com/watch?v=cxryD8ZHCdQ', 'step 1 Heat the oil in a large saucepan or flameproof casserole. Add the spring onions and coriander stalks and cook for 1 min. Add the pork slices and cook for 5 mins until starting to brown. step 2 Stir in the curry paste and peanut butter. After 30 secs, add the sugar, soy and coconut milk, plus ½ can of water. Mix well, put a lid on and leave to simmer for 15 mins, stirring occasionally. step 3 Remove the lid, add the baby corn and increase the heat. Bubble for 3 mins until the corn is cooked and the sauce has thickened a little. Stir in the lime juice and check the seasoning. Can now be frozen for up to 2 months. To cook from frozen: thoroughly defrost, then heat in a pan on the hob until curry is hot all the way through. Serve scattered with the coriander leaves and rice.', 1, NULL, 4, 226, 354, 18.98, 31.92, 32.54, 4.4, 120, 3, 2, 1, 1, 0, 2, '["Thai", "Pork", "Vegetable Oil", "Spring Onions", "Coriander", "Pork Tenderloin", "Thai Red Curry Paste", "Peanut Butter"]', '建议搭配：咖啡', 0, 0, 5.71, '2026-01-12 19:13:00.945', '深圳', 'Android Tablet', '2026-01-12 19:13:00.945', '2026-01-17 02:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000034, 2000002, 'Smoked aubergine purée', 'https://www.themealdb.com/images/media/meals/8c8m4q1763791156.jpg', 'https://www.youtube.com/watch?v=JOXBWo37wWU', 'step 1 Heat grill to very hot. Slice the aubergines in half lengthways, then grill for 25 mins, turning occasionally, until soft – the skin will remain firm, but the flesh will soften. Lift the aubergines off the grill and leave until cool enough to handle. step 2 Using a sharp knife, score the grilled flesh and scoop out the flesh with a spoon. Tip into a bowl and mash with a fork until you get a thick pulp. Beat in the lemon juice and garlic. Add the yogurt and dill, and season. Serve while still warm.', 1, NULL, 3, 204, 673, 25.3, 27.33, 67.01, 4.4, 120, 12, 0, 0, 0, 0, 2, '["Turkish", "Side", "Aubergine", "Lemon", "Garlic", "Yogurt", "Dill"]', '建议搭配：水果', 0, 0, 15.2, '2025-07-07 21:13:00.945', '广州', 'iPad', '2025-07-07 21:13:00.945', '2025-07-13 10:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000035, 2000000, 'Battenberg Cake', 'https://www.themealdb.com/images/media/meals/ywwrsp1511720277.jpg', 'https://www.youtube.com/watch?v=aB41Q7kDZQ0', 'Heat oven to 180C/160C fan/gas 4 and line the base and sides of a 20cm square tin with baking parchment (the easiest way is to cross 2 x 20cm-long strips over the base). To make the almond sponge, put the butter, sugar, flour, ground almonds, baking powder, eggs, vanilla and almond extract in a large bowl. Beat with an electric whisk until the mix comes together smoothly. Scrape into the tin, spreading to the corners, and bake for 25-30 mins – when you poke in a skewer, it should come out clean. Cool in the tin for 10 mins, then transfer to a wire rack to finish cooling while you make the second sponge. For the pink sponge, line the tin as above. Mix all the ingredients together as above, but don’t add the almond extract. Fold in some pink food colouring. Then scrape it all into the tin an', 2, NULL, 5, 192, 427, 39.71, 21.84, 59.51, 3.7, 600, 61, 11, 4, 3, 2, 2, '["Cake", "Sweet", "British", "Dessert", "Butter", "Caster Sugar", "Self-raising Flour", "Almonds", "Baking Powder", "Eggs"]', '建议搭配：咖啡', 0, 0, 0.0, '2025-07-02 14:13:00.945', '武汉', 'iPhone 15', '2025-07-02 14:13:00.945', '2025-07-10 07:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000036, 2000000, 'Smoked Haddock Kedgeree', 'https://www.themealdb.com/images/media/meals/1550441275.jpg', 'https://www.youtube.com/watch?v=QqdzDCWS4gQ', 'Melt 50g butter in a large saucepan (about 20cm across), add 1 finely chopped medium onion and cook gently over a medium heat for 5 minutes, until softened but not browned. Stir in 3 split cardamom pods, ¼ tsp turmeric, 1 small cinnamon stick and 2 bay leaves, then cook for 1 minute. Tip in 450g basmati rice and stir until it is all well coated in the spicy butter. Pour in 1 litre chicken or fish stock, add ½ teaspoon salt and bring to the boil, stir once to release any rice from the bottom of the pan. Cover with a close-fitting lid, reduce the heat to low and leave to cook very gently for 12 minutes. Meanwhile, bring some water to the boil in a large shallow pan. Add 750g un-dyed smoked haddock fillet and simmer for 4 minutes, until the fish is just cooked. Lift it out onto a plate and le', 1, NULL, 4, 229, 594, 29.1, 23.33, 56.86, 4.6, 120, 4, 5, 1, 0, 0, 2, '["Brunch", "Fish", "Fusion", "Indian", "Breakfast", "Butter", "Onion", "Cardamom", "Turmeric", "Cinnamon Stick", "Bay Leaf"]', '建议搭配：清爽沙拉', 0, 0, 0.21, '2025-08-19 05:13:00.945', '杭州', 'HarmonyOS', '2025-08-19 05:13:00.945', '2025-08-19 15:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000037, 2000004, 'Air fryer patatas bravas', 'https://www.themealdb.com/images/media/meals/3m8yae1763257951.jpg', 'https://www.youtube.com/watch?v=kzLaw6PG2UY', 'step 1 Soak the potatoes in just-boiled water for 30 mins, then drain and leave to air-dry for 5 mins. Heat the air fryer to 200C. Tip the potatoes into a bowl and drizzle over 1 tbsp of the oil and add 1/2 tsp each of salt and freshly ground black pepper. Mix to coat the potatoes all over, then tip into the air fryer basket and cook for 20-30 mins until crisp and golden. step 2 Meanwhile, heat the remaining oil in a small pan over a medium-low heat and fry the onion for 8-10 mins until softened but not golden. Stir in the garlic and cook for a minute before adding the paprika and cooking for 30 seconds more. Stir in the tomato purée, cook for 1 min, then tip in the chopped tomatoes. Cook for 5-10 mins over a medium heat until thickened slightly. step 3 Once the potatoes are cooked, tip ou', 1, NULL, 4, 81, 937, 48.39, 13.3, 2.21, 3.9, 120, 5, 0, 2, 0, 0, 2, '["Spanish", "Vegetarian", "Potatoes", "Olive Oil", "Onion", "Garlic", "Paprika", "Tomato Puree"]', '建议搭配：咖啡', 0, 0, 0.0, '2025-10-28 08:13:00.945', '南京', 'iPad', '2025-10-28 08:13:00.945', '2025-11-01 04:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000038, 2000004, 'Beef pho', 'https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg', 'https://www.youtube.com/watch?v=WlosNFMCnE4', 'step 1 Tip the beef stock along with 500ml of water into a large saucepan. Sit the onion and ginger in a frying pan over a high heat and char on all sides, around 3-5 mins (you can also do this under your grill). Once charred, add to the beef stock. In the same pan, toast the spices for 2-3 mins and once they begin to smell fragrant, add them to the beef stock as well. Bring the stock to the boil, then turn to a simmer and cook for 30mins before straining. step 2 Meanwhile, cut the fat from the steak and wrap in cling film, then put into the freezer for 15 mins – this will make your steak really easy to slice! Slice it thinly, then cover with cling film again and pop into the fridge. step 3 Taste the beef stock and use the palm sugar, fish sauce and soy to season. Cook the noodles accordin', 1, NULL, 4, 79, 342, 42.7, 8.77, 25.3, 5.0, 120, 3, 6, 1, 1, 0, 2, '["Vietnamese", "Beef", "Beef Stock", "Onion", "Ginger", "Cinnamon Stick", "Star Anise", "Coriander Seeds"]', '建议搭配：咖啡', 0, 0, 6.46, '2025-11-03 15:13:00.945', '成都', 'Windows Web', '2025-11-03 15:13:00.945', '2025-11-11 06:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000039, 2000001, 'Chakchouka ', 'https://www.themealdb.com/images/media/meals/gpz67p1560458984.jpg', 'https://www.youtube.com/watch?v=EHKNu93MSx4', 'In a large cast iron skillet or sauté pan with a lid, heat oil over medium high heat. Add the onion and sauté for 2-3 minutes, until softened. Add the peppers and garlic, and sauté for an additional 3-5 minutes. Add the tomatoes, cumin, paprika, salt, and chili powder. Mix well and bring the mixture to a simmer. Reduce the heat to medium low and continue to simmer, uncovered, 10-15 minutes until the mixture has thickened to your desired consistency. (Taste the sauce at this point and adjust for salt and spice, as desired.) Using the back of a spoon, make four craters in the mixture, large enough to hold an egg. Crack one egg into each of the craters. Cover the skillet and simmer for 5-7 minutes, until the eggs have set. Serve immediately with crusty bread or pita.', 1, NULL, 3, 81, 1162, 0.0, 36.21, 12.88, 4.8, 240, 18, 10, 3, 1, 0, 2, '["Tunisian", "Miscellaneous", "Tomatoes", "Olive Oil", "Onion", "Red Pepper", "Green Pepper", "Garlic"]', '建议搭配：气泡水', 0, 0, 12.79, '2025-06-17 22:13:00.945', '成都', 'HarmonyOS', '2025-06-17 22:13:00.945', '2025-06-27 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000040, 2000001, 'Ratatouille', 'https://www.themealdb.com/images/media/meals/wrpwuu1511786491.jpg', 'https://www.youtube.com/watch?v=BFdQUgAFtGU', 'Cut the aubergines in half lengthways. Place them on the board, cut side down, slice in half lengthways again and then across into 1.5cm chunks. Cut off the courgettes ends, then across into 1.5cm slices. Peel the peppers from stalk to bottom. Hold upright, cut around the stalk, then cut into 3 pieces. Cut away any membrane, then chop into bite-size chunks. Score a small cross on the base of each tomato, then put them into a heatproof bowl. Pour boiling water over the tomatoes, leave for 20 secs, then remove. Pour the water away, replace the tomatoes and cover with cold water. Leave to cool, then peel the skin away. Quarter the tomatoes, scrape away the seeds with a spoon, then roughly chop the flesh. Set a sauté pan over medium heat and when hot, pour in 2 tbsp olive oil. Brown the auberg', 1, NULL, 5, 240, 738, 26.57, 26.09, 24.08, 4.1, 1080, 45, 41, 10, 5, 1, 2, '["Vegetables", "SideDish", "French", "Vegetarian", "Aubergine", "Courgettes", "Yellow Pepper", "Tomato", "Olive Oil", "Basil"]', '建议搭配：热汤', 0, 0, 10.71, '2025-10-24 01:13:00.945', '西安', 'HarmonyOS', '2025-10-24 01:13:00.945', '2025-10-26 20:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000041, 2000004, 'Beef Mechado', 'https://www.themealdb.com/images/media/meals/cgl60b1683206581.jpg', 'https://www.youtube.com/watch?v=jxW3Lj8VjyE', '0.	Make the beef tenderloin marinade by combining soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt, and ground black pepper in a large bowl. Mix well. 1.	Add the cubed beef tenderloin to the bowl with the beef tenderloin marinade. Gently toss to coat the beef. Let it stay for 1 hour. 2.	Using a metal or bamboo skewer, assemble the beef kebob by skewering the vegetables and marinated beef tenderloin. 3.	Heat-up the grill and start grilling the beef kebobs for 3 minutes per side. This will give you a medium beef that is juicy and tender on the inside. Add more time if you want your beef well done, but it will be less tender. 4.	Transfer to a serving plate. Serve with Saffron rice. 5.	Share and enjoy!', 1, NULL, 4, 87, 218, 11.96, 26.7, 50.19, 4.7, 240, 15, 7, 1, 2, 1, 2, '["Stew", "Warming", "Filipino", "Beef", "Garlic", "Onion", "Tomato Puree", "Water", "Olive Oil"]', '建议搭配：水果', 0, 0, 0.0, '2026-02-01 02:13:00.945', '广州', 'Windows Web', '2026-02-01 02:13:00.945', '2026-02-02 16:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000042, 2000003, 'English Breakfast', 'https://www.themealdb.com/images/media/meals/utxryw1511721587.jpg', 'https://www.youtube.com/watch?v=FXjYU2Ensck', 'Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil. Cook the sausages first. Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden. After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients. If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven. Snip a few small cuts into the fatty edge of the bacon. Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached. Like the sausages, the cooked bacon can be kept hot on a plate in the oven. For the mushrooms, brush away a', 1, NULL, 5, 230, 811, 36.31, 0.01, 47.25, 4.6, 120, 8, 4, 1, 1, 0, 2, '["Breakfast", "British", "Sausages", "Bacon", "Mushrooms", "Tomatoes", "Black Pudding", "Eggs"]', '建议搭配：清爽沙拉', 0, 1, 3.79, '2026-01-11 00:13:00.945', '武汉', 'iPad', '2026-01-11 00:13:00.945', '2026-01-15 18:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000043, 2000001, 'Lamb & apricot meatballs', 'https://www.themealdb.com/images/media/meals/72fgzj1764109947.jpg', 'https://www.youtube.com/watch?v=o0UbzRZw-GQ', 'step 1 Heat 2 tsp oil in a pan and soften the onions for 5 mins. Add the garlic and spices and cook for a few mins more. Spoon half the onion mixture into a bowl and set aside to cool. Add the tomatoes, sugar and seasoning to the remaining onions in the pan and simmer for about 10 mins until reduced. step 2 Meanwhile, add the mint, lamb, apricots and breadcrumbs to the cooled onions, season and mix well with your hands. Shape into little meatballs. step 3 Heat the rest of the oil in a non-stick pan and fry the meatballs until golden (in batches if you need to). Stir in the sauce with a splash of water and gently cook everything for a few mins until the meatballs are cooked through. Serve with pitta bread and salad.', 1, NULL, 4, 150, 408, 20.12, 39.35, 0.0, 4.5, 120, 17, 2, 1, 0, 0, 2, '["Turkish", "Lamb", "Olive Oil", "Red Onions", "Garlic", "Ground Cumin", "Ground Coriander", "Tinned Tomatos"]', '建议搭配：咖啡', 0, 0, 0.0, '2025-09-09 08:13:00.945', '武汉', 'HarmonyOS', '2025-09-09 08:13:00.945', '2025-09-10 16:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000044, 2000000, 'Callaloo and SaltFish', 'https://www.themealdb.com/images/media/meals/73o3vq1765317873.jpg', 'https://www.youtube.com/watch?v=n1fRCk-zTRM', 'Soak salted fish in water overnight. Next, heat salted fish in water on stove until water boils. You should see a foam on top. Remove from heat and drain. Set aside and shred salted fish once it cools. Cook bacon in skillet over medium heat until crispy. Remove bacon from heat and drain the majority of the bacon grease, leaving about 1 tablespoon in the skillet. Add yellow onion, green onion, scotch bonnet pepper, and garlic to the skillet and stir. Cook for about 2 minutes or until onions soften. Add salted fish to skillet and stir. Cook for about a minute. Next, add callaloo, roma tomatoes, thyme, and black pepper. Stir to combine and cook until heated through, about 2 minutes. Enjoy', 1, NULL, 4, 191, 548, 31.33, 17.94, 110.97, 5.0, 240, 12, 5, 0, 3, 0, 2, '["Jamaican", "Side", "Salt Cod", "Bacon", "Callaloo", "Onion", "Spring Onions", "Garlic"]', '建议搭配：水果', 0, 0, 2.7, '2025-12-24 20:13:00.945', '苏州', 'iPad', '2025-12-24 20:13:00.945', '2025-12-30 12:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000045, 2000000, 'Chorizo, potato & cheese omelette', 'https://www.themealdb.com/images/media/meals/0y6uvc1763258983.jpg', 'https://www.youtube.com/watch?v=K2Ba5BWYXUU', 'step 1 Cook the potato in boiling water for 8-10 mins or until tender. Drain and allow to steam-dry. Heat oil in an omelette pan, add chorizo and cook for 2 mins. Add the potato and cook for a further 5 mins until the potato starts to crisp. Spoon pan contents out, wipe pan and cook a 2 or 3-egg omelette in the same pan. When almost cooked, scatter with the chorizo and potato, parsley and cheese. Fold the omelette in the pan and cook for 1 min more to melt the cheese.', 1, NULL, 3, 135, 779, 20.85, 36.1, 36.17, 4.0, 600, 35, 9, 0, 3, 0, 2, '["Cheesy", "Spanish", "Pork", "Potatoes", "Olive Oil", "Chorizo", "Egg", "Parsley", "Cheddar Cheese"]', '建议搭配：热汤', 0, 1, 3.75, '2025-07-13 13:13:00.945', '西安', 'Android 14 Pixel', '2025-07-13 13:13:00.945', '2025-07-19 09:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000046, 2000003, 'Aubergine couscous salad', 'https://www.themealdb.com/images/media/meals/02s6gc1763799560.jpg', 'https://www.youtube.com/shorts/8ws2Ohy__CQ', 'step 1 Heat grill to high. Put the aubergine on a baking sheet, brush with oil and season. Grill for about 15 mins, turning and brushing with more oil halfway, until browned and softened. step 2 Meanwhile, tip the couscous into a large bowl, pour over the stock, then cover and leave for 10 mins. Mix the tomatoes, mint, goat’s cheese and remaining oil together. Fluff the couscous up with a fork, then stir in the aubergines, tomato mixture and lemon juice.', 1, NULL, 3, 42, 218, 0.0, 46.16, 67.18, 3.6, 480, 35, 14, 8, 4, 2, 2, '["Turkish", "Vegetarian", "Aubergine", "Olive Oil", "Couscous", "Vegetable Stock", "Cherry Tomatoes", "Mint"]', '建议搭配：气泡水', 0, 0, 5.01, '2026-01-23 23:13:00.945', '杭州', 'iPad', '2026-01-23 23:13:00.945', '2026-01-30 20:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000047, 2000002, 'Spanish beans with chicken & chorizo', 'https://www.themealdb.com/images/media/meals/bpkxtw1763332446.jpg', '', 'step 1 Soak the beans for at least 4 hrs or overnight in a large bowl with plenty of water to cover. Next day, rinse and drain, then put in a large heavy based pan with the onion, paprika, herb bundle and chicken. Pour over enough water or stock to cover, bring to the boil, then reduce the heat, cover and simmer for 45 mins. step 2 Remove the chicken to a plate, then add the potatoes and chorizo to the pan. Continue cooking for 30 mins until the beans and potatoes are tender. step 3 Discard the skin and bones from the chicken and tear into large chunks. Return the chicken to the pan with the spinach and simmer for 5 mins.', 1, NULL, 3, 97, 557, 34.04, 12.74, 75.34, 4.1, 240, 21, 1, 3, 0, 0, 2, '["Spanish", "Chicken", "Pinto Beans", "Onion", "Paprika", "Thyme", "Bay Leaves", "Parsley"]', '建议搭配：水果', 0, 0, 8.03, '2025-04-16 07:13:00.945', '青岛', 'iPad', '2025-04-16 07:13:00.945', '2025-04-19 12:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000048, 2000002, 'Hummus', 'https://www.themealdb.com/images/media/meals/gpon5u1763801180.jpg', 'https://www.youtube.com/watch?v=EsZFJEjANiA', 'step 1 Drain the chickpeas into a sieve set over a bowl or jug to catch the liquid. Tip the chickpeas, tahini, garlic and yogurt into a food processor or blender and whizz to smooth. step 2 Whizz in a tbsp of the chickpea liquid at a time until you have a nice consistency, then scrape into a bowl. step 3 Stir in a squeeze of lemon juice and season to taste.', 1, NULL, 2, 116, 621, 23.39, 19.08, 43.12, 4.1, 120, 6, 5, 0, 0, 0, 2, '["Turkish", "Side", "Chickpeas", "Tahini Paste", "Garlic Clove", "Greek Yogurt", "Lemon"]', '建议搭配：气泡水', 0, 0, 13.58, '2026-01-25 16:13:00.945', '重庆', 'iPad', '2026-01-25 16:13:00.945', '2026-02-03 11:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000049, 2000001, 'Paszteciki (Polish Pasties)', 'https://www.themealdb.com/images/media/meals/c9a3l31593261890.jpg', 'https://www.youtube.com/watch?v=qANmR6BBJpQ', 'Sift flour and salt into a large mixing bowl. Use a spoon to push the egg yolk through a fine sieve into the flour. Add the raw egg and mix well. Beat in butter 1 tablespoon at a time. Place dough on a floured surface and knead until smooth and elastic, then wrap in waxed paper and refrigerate until firm (at least 30 minutes). In a heavy skillet, melt 2 tablespoons butter over medium heat; saute the onion and rutabaga until the onion is soft and transparent (5 minutes). Put the onions, rutabaga, and beef through a meat grinder twice if you have one, if not just chop them up as fine as possible. Melt the remaining 4 tablespoons butter over medium heat, and add the meat mixture. Cook over low heat, stirring occasionally, until all of the liquid has evaporated and the mixture is thick enough ', 1, NULL, 5, 109, 519, 45.33, 9.21, 40.53, 4.2, 120, 9, 2, 1, 0, 0, 2, '["Polish", "Beef", "Flour", "Salt", "Egg", "Butter"]', '建议搭配：热汤', 0, 0, 2.15, '2026-01-30 17:13:00.945', '深圳', 'Mac Safari', '2026-01-30 17:13:00.945', '2026-02-07 19:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000050, 2000002, 'Chtitha Batata (Algerian Potato Stew)', 'https://www.themealdb.com/images/media/meals/q8pu1k1764114334.jpg', 'https://www.youtube.com/watch?v=kpsZQTVVjdk', 'Combine garlic, chile pepper, cumin, paprika, black pepper, cayenne, and salt in a mortar; grind with a pestle until it forms a paste. Add olive oil and mix dersa well. Heat a large saucepan over medium heat and stir-fry dersa until fragrant, 2 to 4 minutes. Add potato halves and stir to combine with the dersa. Stir in tomato paste. Pour in enough water to just cover the potatoes and bring to a boil. Reduce heat and simmer until potatoes are tender, about 40 minutes. Ladle potatoes into a serving bowl. Spoon any remaining sauce over the potatoes.', 1, NULL, 3, 84, 567, 26.99, 29.57, 100.26, 3.9, 120, 6, 5, 1, 0, 0, 2, '["Algerian", "Vegetarian", "Garlic", "Red Chilli", "Ground Cumin", "Paprika", "Black Pepper", "Cayenne Pepper"]', '建议搭配：水果', 0, 0, 3.17, '2026-01-15 17:13:00.945', '青岛', 'Windows Web', '2026-01-15 17:13:00.945', '2026-01-20 05:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000051, 2000001, 'Wontons', 'https://www.themealdb.com/images/media/meals/1525876468.jpg', 'https://www.youtube.com/watch?v=9h9No18ZyCI', 'Combine pork, garlic, ginger, soy sauce, sesame oil, and vegetables in a bowl. Separate wonton skins. Place a heaping teaspoon of filling in the center of the wonton. Brush water on 2 borders of the skin, covering 1/4 inch from the edge. Fold skin over to form a triangle, sealing edges. Pinch the two long outside points together. Heat oil to 450 degrees and fry 4 to 5 at a time until golden. Drain and serve with sauce.', 1, NULL, 3, 99, 759, 27.45, 0.0, 29.75, 4.4, 1800000, 202466, 108887, 14162, 2008, 1700, 2, '["MainMeal", "Chinese", "Pork", "Garlic Clove", "Ginger", "Soy Sauce", "Sesame Seed Oil", "Carrots"]', '建议搭配：咖啡', 0, 0, 6.57, '2025-09-10 16:13:00.945', '苏州', 'Android Tablet', '2025-09-10 16:13:00.945', '2025-09-17 17:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000052, 2000002, 'Spotted Dick', 'https://www.themealdb.com/images/media/meals/xqvyqr1511638875.jpg', 'https://www.youtube.com/watch?v=fu15XOF-ros', 'Put the flour and salt in a bowl. Add the suet, currants, sugar, lemon and orange zest. Pour in 150ml milk and mix to a firm but moist dough, adding the extra milk if necessary. Shape into a fat roll about 20cm long. Place on a large rectangle of baking parchment. Wrap loosely to allow for the pudding to rise and tie the ends with string like a Christmas cracker. Place a steamer over a large pan of boiling water, add the pudding to the steamer, cover and steam for 1 1/2 hours. Top up the pan with water from time to time. Remove from the steamer and allow to cool slightly before unwrapping. Serve sliced with custard.', 2, NULL, 3, 164, 418, 17.12, 4.72, 9.94, 4.0, 600, 66, 1, 8, 4, 0, 2, '["Fruity", "Pudding", "Desert", "British", "Dessert", "Self-raising Flour", "Salt", "Suet", "Currants", "Caster Sugar", "Lemon"]', '建议搭配：咖啡', 0, 0, 7.25, '2025-11-04 13:13:00.945', '武汉', 'iPad', '2025-11-04 13:13:00.945', '2025-11-05 21:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000053, 2000004, 'Pistachio cake', 'https://www.themealdb.com/images/media/meals/xvgpng1764121726.jpg', 'https://www.youtube.com/watch?v=ACpikfieDP0', 'Heat the oven to 180C/160C fan/gas 4. Butter and line a 23cm springform cake tin. Tip 150g of the pistachios into a food processor and blitz until finely ground. Tip into a bowl and mix in the flour, baking powder and pinch of salt. Beat the butter and sugar in a separate bowl until fluffy and pale, around 5 mins. Crack in the eggs one at a time, beating well for 1 min after each addition, until they have all been added. Beat in the vanilla, then fold in the flour mixture gently. Carefully spoon into the prepared tin and bake for 35-40 mins until a skewer inserted into the middle comes out clean. Set aside to cool completely on a wire rack in the tin. step 2 Meanwhile, sift the icing sugar into a bowl, then tip in the mascarpone, double cream and pistachio paste. Beat until well combined, ', 2, NULL, 5, 233, 538, 24.91, 27.01, 65.03, 4.3, 120, 10, 6, 1, 1, 0, 2, '["Polish", "Dessert", "Butter", "Pistachio", "Plain Flour", "Baking Powder", "Caster Sugar", "Egg"]', '建议搭配：气泡水', 0, 0, 2.82, '2025-09-12 03:13:00.945', '杭州', 'HarmonyOS', '2025-09-12 03:13:00.945', '2025-09-15 02:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000054, 2000001, 'Oatmeal pancakes', 'https://www.themealdb.com/images/media/meals/c400ok1764439058.jpg', 'https://www.youtube.com/watch?v=kkrRFWN4LG4', 'Place all the ingredients in the glass and beat. Let the mixture stand for 10 minutes. Grease a hot frying pan with a little butter and pour a little of the mixture. When it starts to bubble on the surface, turn over with a spatula. Cook over medium-low heat so that they do not burn. Finally, add the caramel and strawberries.', 1, NULL, 2, 67, 573, 21.43, 21.54, 77.27, 4.2, 120, 4, 2, 1, 0, 0, 2, '["Venezulan", "Breakfast", "Egg", "Milk", "Sugar", "Baking Powder", "Salt", "Vanilla Extract"]', '建议搭配：热汤', 0, 0, 5.04, '2025-08-01 19:13:00.945', '苏州', 'Android 14 Pixel', '2025-08-01 19:13:00.945', '2025-08-10 09:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000055, 2000004, 'Moroccan Carrot Soup', 'https://www.themealdb.com/images/media/meals/jcr46d1614763831.jpg', 'https://www.youtube.com/watch?v=7tDWOpnIhok', 'Step 1 Preheat oven to 180° C. Step 2 Combine carrots, onion, garlic, cumin seeds, coriander seeds, salt and olive oil in a bowl and mix well. Transfer on a baking tray. Step 3 Put the baking tray in preheated oven and roast for 10-12 minutes or till carrots soften. Remove from heat and cool. Step 4 Grind the baked carrot mixture along with some water to make a smooth paste and strain in a bowl. Step 5 Heat the carrot mixture in a non-stick pan. Add two cups of water and bring to a boil. Add garam masala powder and mix. Add salt and mix well. Step 6 Remove from heat, add lemon juice and mix well. Step 7 Serve hot.', 1, NULL, 5, 196, 537, 13.71, 31.23, 78.03, 3.9, 120, 11, 5, 0, 0, 0, 2, '["Soup", "Moroccan", "Vegetarian", "Carrots", "Onion", "Garlic Clove", "Cumin", "Coriander", "Olive Oil"]', '建议搭配：热汤', 0, 1, 0.0, '2025-05-18 10:13:00.945', '广州', 'iPad', '2025-05-18 10:13:00.945', '2025-05-23 05:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000056, 2000004, 'Bakewell tart', 'https://www.themealdb.com/images/media/meals/wyrqqq1468233628.jpg', 'https://www.youtube.com/watch?v=1ahpSTf_Pvk', 'To make the pastry, measure the flour into a bowl and rub in the butter with your fingertips until the mixture resembles fine breadcrumbs. Add the water, mixing to form a soft dough. Roll out the dough on a lightly floured work surface and use to line a 20cm/8in flan tin. Leave in the fridge to chill for 30 minutes. Preheat the oven to 200C/400F/Gas 6 (180C fan). Line the pastry case with foil and fill with baking beans. Bake blind for about 15 minutes, then remove the beans and foil and cook for a further five minutes to dry out the base. For the filing, spread the base of the flan generously with raspberry jam. Melt the butter in a pan, take off the heat and then stir in the sugar. Add ground almonds, egg and almond extract. Pour into the flan tin and sprinkle over the flaked almonds. Ba', 2, NULL, 4, 36, 307, 22.8, 37.72, 65.15, 4.0, 960, 65, 20, 1, 4, 2, 2, '["Tart", "Baking", "Alcoholic", "British", "Dessert", "plain flour", "chilled butter", "cold water", "raspberry jam", "butter", "caster sugar"]', '建议搭配：热汤', 0, 0, 15.81, '2025-11-25 12:13:00.945', '北京', 'iPad', '2025-11-25 12:13:00.945', '2025-11-30 20:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000057, 2000001, 'Salmon Eggs Eggs Benedict', 'https://www.themealdb.com/images/media/meals/1550440197.jpg', 'https://www.youtube.com/watch?v=Woiiet4vQ58', 'First make the Hollandaise sauce. Put the lemon juice and vinegar in a small bowl, add the egg yolks and whisk with a balloon whisk until light and frothy. Place the bowl over a pan of simmering water and whisk until mixture thickens. Gradually add the butter, whisking constantly until thick – if it looks like it might be splitting, then whisk off the heat for a few mins. Season and keep warm. To poach the eggs, bring a large pan of water to the boil and add the vinegar. Lower the heat so that the water is simmering gently. Stir the water so you have a slight whirlpool, then slide in the eggs one by one. Cook each for about 4 mins, then remove with a slotted spoon. Lightly toast and butter the muffins, then put a couple of slices of salmon on each half. Top each with an egg, spoon over som', 1, NULL, 3, 143, 411, 64.82, 26.8, 91.33, 4.4, 1680, 22, 87, 8, 16, 4, 2, '["Bun", "Brunch", "American", "Breakfast", "Eggs", "White Wine Vinegar", "English Muffins", "Butter", "Smoked Salmon", "Lemon Juice"]', '建议搭配：气泡水', 0, 0, 4.79, '2025-04-28 01:13:00.945', '成都', 'Android Tablet', '2025-04-28 01:13:00.945', '2025-05-06 21:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000058, 2000003, 'Prawn stir-fry', 'https://www.themealdb.com/images/media/meals/96lt871763480970.jpg', 'https://www.youtube.com/watch?v=DddM8OGb4Jc', 'step 1 Put the prawns in a bowl. Put the chilli, garlic, coriander stalks (snip these up using scissors first) and caster sugar in a spice grinder or small food processor and whizz together. Add half of the lime juice and the fish sauce, then pour this over the prawns. step 2 Heat 1 tbsp oil in a wok, add the ginger and spring onions and fry for 1 min. Add the red pepper and fry for 1 min, until the pepper starts to soften. Add the water chestnuts and bean sprouts, and toss together until the bean sprouts start to wilt. Add the soy sauce and a really good grind of black pepper, then tip the lot into a serving dish. step 3 Heat the remaining oil in the wok and add the prawns, lifting them out of their juices. Toss for 1-2 mins until they turn pink, add the marinade and swirl the wok quickly', 1, NULL, 4, 120, 319, 40.29, 11.05, 67.03, 4.2, 240, 13, 11, 1, 0, 0, 2, '["Thai", "Seafood", "Raw tiger prawns", "Green Chilli", "Garlic", "Coriander", "Caster Sugar", "Lime"]', '建议搭配：咖啡', 0, 0, 0.0, '2025-09-24 03:13:00.945', '武汉', 'Mac Safari', '2025-09-24 03:13:00.945', '2025-09-28 14:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000059, 2000000, 'Broccoli & Stilton soup', 'https://www.themealdb.com/images/media/meals/tvvxpv1511191952.jpg', 'https://www.youtube.com/watch?v=_HgVLpmNxTY', 'Heat the rapeseed oil in a large saucepan and then add the onions. Cook on a medium heat until soft. Add a splash of water if the onions start to catch. Add the celery, leek, potato and a knob of butter. Stir until melted, then cover with a lid. Allow to sweat for 5 minutes. Remove the lid. Pour in the stock and add any chunky bits of broccoli stalk. Cook for 10 – 15 minutes until all the vegetables are soft. Add the rest of the broccoli and cook for a further 5 minutes. Carefully transfer to a blender and blitz until smooth. Stir in the stilton, allowing a few lumps to remain. Season with black pepper and serve.', 3, NULL, 4, 49, 589, 43.49, 14.59, 70.62, 3.7, 120, 7, 4, 1, 1, 0, 2, '["Soup", "Cheesy", "British", "Starter", "Rapeseed Oil", "Onion", "Celery", "Leek", "Potatoes", "Butter"]', '建议搭配：气泡水', 0, 0, 2.79, '2026-02-03 06:13:00.945', '杭州', 'Android 14 Pixel', '2026-02-03 06:13:00.945', '2026-02-08 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000060, 2000002, 'Prawn & noodle salad with crispy shallots', 'https://www.themealdb.com/images/media/meals/0iryz91763778419.jpg', '', 'step 1 For the crispy shallots, heat 5cm of oil until hot in a wok. You will know the oil is hot enough when one piece of shallot sizzles as soon as it’s dropped in. Toss the shallot slices with flour, shake off excess and fry in the oil until golden. They fry quickly, about 1 min. Drain on kitchen paper, sprinkle with salt and set aside. step 2 To make the dressing, mix the lime juice, sugar, fish sauce and garlic and set aside. In a large mixing bowl, pour boiling water over the noodles. Leave them for 2 mins or until they are just cooked, then rinse under cold water. Drain well, shaking the sieve numerous times to get out the excess water, then place back in the bowl. Add prawns, onion, chilli, cucumber and herbs. Pour the dressing over, mix, then sprinkle with the shallots and peanuts.', 1, NULL, 4, 228, 675, 39.04, 12.22, 142.67, 3.9, 1200, 137, 36, 16, 3, 2, 2, '["Vietnamese", "Seafood", "Rice Noodles", "Prawns", "Red Onions", "Red Chilli", "Cucumber", "Coriander"]', '建议搭配：气泡水', 0, 0, 2.2, '2025-03-30 12:13:00.945', '西安', 'Windows Web', '2025-03-30 12:13:00.945', '2025-04-02 21:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000061, 2000001, 'Spaghetti alla Carbonara', 'https://www.themealdb.com/images/media/meals/llcbn01574260722.jpg', 'https://www.youtube.com/watch?v=_T6jkRvhlkk', 'STEP 1 Put a large saucepan of water on to boil. STEP 2 Finely chop the 100g pancetta, having first removed any rind. Finely grate 50g pecorino cheese and 50g parmesan and mix them together. STEP 3 Beat the 3 large eggs in a medium bowl and season with a little freshly grated black pepper. Set everything aside. STEP 4 Add 1 tsp salt to the boiling water, add 350g spaghetti and when the water comes back to the boil, cook at a constant simmer, covered, for 10 minutes or until al dente (just cooked). STEP 5 Squash 2 peeled plump garlic cloves with the blade of a knife, just to bruise it. STEP 6 While the spaghetti is cooking, fry the pancetta with the garlic. Drop 50g unsalted butter into a large frying pan or wok and, as soon as the butter has melted, tip in the pancetta and garlic. STEP 7 L', 1, NULL, 5, 197, 802, 20.58, 22.41, 59.83, 4.1, 360, 12, 10, 1, 2, 1, 2, '["Pasta", "BBQ", "Breakfast", "Italian", "Spaghetti", "Egg Yolks", "Salt", "Bacon", "Pecorino", "Black Pepper"]', '建议搭配：气泡水', 0, 0, 7.47, '2025-11-02 04:13:00.945', '深圳', 'Android Tablet', '2025-11-02 04:13:00.945', '2025-11-10 12:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000062, 2000004, 'Arroz al horno (baked rice)', 'https://www.themealdb.com/images/media/meals/qt4i0n1763256454.jpg', 'https://www.youtube.com/watch?v=f-waAIrn2iA', 'step 1 Heat oven to 200C/180C/gas 6. Heat half the oil in a deep frying or sauté pan (or shallow casserole dish) measuring around 30cm in diameter. Over a high heat, colour the pork belly slices on each side in several batches, then transfer to a bowl. Add the remaining oil to the pan and lower the heat to medium, then add the black pudding and bacon and fry all over for several mins. Remove with a slotted spoon. Fry the onion and peppers for around 10 mins until soft and pale gold, then add the tomato and cook until soft. Add the garlic, smoked paprika and chilli flakes and cook for another 2 mins, then put the pork, black pudding and bacon back in the pan. Add the beans, stock and whichever herb you''re using, and bring everything to the boil. step 2 Sprinkle the rice around the pork bell', 1, NULL, 5, 240, 565, 20.32, 32.39, 83.1, 4.2, 120, 6, 1, 0, 0, 0, 2, '["Spanish", "Pork", "Extra Virgin Olive Oil", "Pork belly slices", "Black Pudding", "Bacon lardon", "Onion", "Red Pepper"]', '建议搭配：清爽沙拉', 0, 0, 8.78, '2025-09-18 22:13:00.945', '上海', 'Windows Web', '2025-09-18 22:13:00.945', '2025-09-28 15:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000063, 2000004, 'Falafel Pita Sandwich with Tahini Sauce', 'https://www.themealdb.com/images/media/meals/ae6clc1760524712.jpg', 'https://www.youtube.com/watch?v=wt8nApxP5fE', 'Preheat the oven to 450 degrees F (230 degrees C). Place falafel on a baking sheet. Bake in the preheated oven until heated through, 8 to 10 minutes. While falafel bake, whisk tahini, water, lemon juice, garlic, and paprika together in a bowl. Cut about 1 inch from the top of each pita to form a pocket. Add 2 falafel to each pita with equal amounts lettuce, tomato, cucumber, pickle, and red onion. Drizzle each with about 1 tablespoon tahini sauce and some harissa.', 1, NULL, 2, 102, 555, 0.0, 18.43, 70.21, 3.6, 2280, 60, 95, 39, 9, 4, 2, '["Syrian", "Vegetarian", "Falafel", "Tahini", "Water", "Lemon Juice", "Garlic", "Paprika"]', '建议搭配：热汤', 0, 0, 2.6, '2025-09-26 06:13:00.945', '苏州', 'Mac Safari', '2025-09-26 06:13:00.945', '2025-09-30 13:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000064, 2000000, 'Stamppot', 'https://www.themealdb.com/images/media/meals/hyarod1565090529.jpg', 'https://www.youtube.com/watch?v=hTrSXryX31A', 'Wash and peel the potatoes and cut into similarly sized pieces for even cooking. In a large soup pot, boil the potatoes and the bay leaves in salted water for 20 minutes. Discard the bay leaves. If you''re not using a bag of ready-cut curly kale, wash the bunches thoroughly under cool running water to get rid of all soil—you wouldn''t want that gritty texture in your finished dish. Trim any coarse stems and discard any brown leaves. With a sharp knife, cut the curly kale into thin strips. Peel and chop the shallots. In a frying pan or skillet, melt 1 tbsp. of butter and saute the shallots for a few minutes before adding the curly kale and 2 tbsp. of water. Season and cook for about 10 minutes, or until tender. Warm the milk on the stove or in the microwave. Drain, shake and dry the potatoes ', 1, NULL, 5, 205, 313, 15.73, 6.84, 26.95, 4.2, 1200, 97, 19, 4, 4, 2, 2, '["Savory", "Breakfast", "Dutch", "Pork", "Potatoes", "Bay Leaf", "Shallots", "Butter", "Kale", "Sausages"]', '建议搭配：气泡水', 0, 0, 2.06, '2025-05-07 08:13:00.945', '苏州', 'Windows Web', '2025-05-07 08:13:00.945', '2025-05-08 02:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000065, 2000002, 'Home-made Mandazi', 'https://www.themealdb.com/images/media/meals/thazgm1555350962.jpg', '', 'This is one recipe a lot of people have requested and I have tried to make it as simple as possible and I hope it will work for you. Make sure you use the right flour which is basically one with raising agents. Adjust the amount of sugar to your taste and try using different flavours to have variety whenever you have them. You can use Coconut milk instead of regular milk, you can also add desiccated coconut to the dry flour or other spices like powdered cloves or cinnamon. For “healthy looking” mandazis do not roll the dough too thin before frying and use the procedure I have indicated above. 1. Mix the flour,cinnamon and sugar in a suitable bowl. 2. In a separate bowl whisk the egg into the milk 3. Make a well at the centre of the flour and add the milk and egg mixture and slowly mix to f', 1, NULL, 4, 197, 559, 16.3, 38.78, 54.45, 4.2, 240, 11, 9, 3, 1, 0, 2, '["Baking", "Breakfast", "Egg", "Warm", "Snack", "Kenyan", "Self-raising Flour", "Sugar", "Eggs", "Milk"]', '建议搭配：气泡水', 0, 0, 2.86, '2025-12-16 16:13:00.945', '西安', 'iPhone 15', '2025-12-16 16:13:00.945', '2025-12-22 16:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000066, 2000002, 'Algerian Carrots', 'https://www.themealdb.com/images/media/meals/o2cd4r1764113576.jpg', 'https://www.youtube.com/watch?v=mF2ND56szUQ', 'Place a steamer insert into a saucepan, and fill with 1 1/2 cups of water, or just below the bottom of the steamer. Cover, and bring the water to a boil over high heat. Add the sliced carrots, reduce the heat to medium, and cover the pan again. Steam until tender but not mushy, 4 to 6 minutes depending on the thickness of the slices. Reserve 1/2 cup of the cooking liquid. Heat the olive oil in a skillet over medium heat. Reduce the heat to low and stir in the salt, pepper, cinnamon, cumin, garlic, and thyme. Cook the spices and garlic, stirring frequently, until fragrant, about 10 minutes. Add the 1/2 cup reserved cooking liquid and the bay leaf, cover, and simmer for 20 minutes. Stir in the carrots, tossing well to coat with the spice mixture, and cook until heated through, about 2 to 3 m', 1, NULL, 3, 84, 188, 9.54, 9.85, 74.8, 4.3, 600, 62, 24, 10, 8, 0, 2, '["Algerian", "Side", "Water", "Carrots", "Olive Oil", "Salt", "Black Pepper", "Ground Cinnamon"]', '建议搭配：气泡水', 0, 0, 10.71, '2025-04-12 08:13:00.945', '苏州', 'Mac Safari', '2025-04-12 08:13:00.945', '2025-04-20 23:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000067, 2000000, 'Portuguese barbecued pork (Febras assadas)', 'https://www.themealdb.com/images/media/meals/cybyue1614349443.jpg', 'https://www.youtube.com/watch?v=tVpsZaejyYU', 'STEP 1 Cut the tenderloins into 5 equal-size pieces leaving the tail ends a little longer. Take a clear plastic bag and slip one of the pieces in. Bash it into an escalope the size of a side-plate with a rolling pin and repeat with the remaining pieces. STEP 2 Put the wine, paprika, some salt and pepper and the juice of ½ a lemon in a bowl and add the pork. Leave to marinate for 20-30 minutes, while you get your barbecue to the stage where the coals are glowing but there are no flames. STEP 3 To make the chips, fill a basin with cool water and cut the potatoes into 3cm-thick chips. Soak them in the water for 5 minutes and then change the water. Leave for 5 more minutes. Drain and then pat dry on a towel or with kitchen paper. STEP 4 Heat the oil in a deep fryer or a deep heavy-based pan wi', 1, NULL, 5, 140, 682, 50.41, 10.44, 33.19, 4.5, 120, 8, 5, 1, 1, 0, 2, '["Portuguese", "Pork", "White Wine", "Paprika", "Lemon", "Lemon Juice", "Olive Oil"]', '建议搭配：水果', 0, 1, 0.0, '2025-08-12 01:13:00.945', '南京', 'iPhone 15', '2025-08-12 01:13:00.945', '2025-08-18 20:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000068, 2000002, 'Fårikål (Norwegian National Dish)', 'https://www.themealdb.com/images/media/meals/ttfxxn1762773067.jpg', 'https://www.youtube.com/shorts/2mMT71Knp8E', '▢ Cut the lamb into large pieces. ▢ Slice the cabbage into large wedges, keeping the core attached. ▢ Add a layer of lamb pieces to the bottom of a large pot, fatty side down. Sprinkle with peppercorns and salt. Add a layer of cabbage wedges on top. Repeat with more layers of lamb, peppercorns, and cabbage, ending with cabbage on top. ▢ Optional: Sprinkle a couple of tablespoons on top of the lamb for a thicker stew. ▢ Add water to the pot and bring to a boil. Cover and reduce heat. Cook on low heat for 2 – 3 hours, until the lamb gently falls away from the bone. ▢ Serve with boiled potatoes and fresh parsley, covering generously with the fårikål broth.', 1, NULL, 3, 82, 1057, 34.86, 37.94, 76.5, 5.0, 120, 4, 4, 2, 0, 0, 2, '["Norwegian", "Lamb", "White Cabbage", "Whole black peppercorns", "Salt", "Water", "Flour"]', '建议搭配：清爽沙拉', 0, 0, 13.33, '2025-07-07 11:13:00.945', '南京', 'iPhone 15', '2025-07-07 11:13:00.945', '2025-07-15 19:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000069, 2000001, 'Spanish tomato bread with jamón Serrano', 'https://www.themealdb.com/images/media/meals/hsp1fo1763327867.jpg', 'https://www.youtube.com/watch?v=OG9zuXJht7I', 'step 1 Mix together the chopped tomatoes, garlic clove, olive oil, salt and pepper. Keep in the fridge until needed. step 2 To serve, toast 20 slices of baguette. Spoon a little tomato topping on to each piece of toast. Tear 5-6 slices of jamón Serrano into pieces and put one piece on each slice of bread.', 1, NULL, 2, 104, 406, 24.37, 32.98, 21.39, 4.4, 120, 10, 3, 1, 0, 0, 2, '["Spanish", "Pork", "Tomato", "Garlic", "Olive Oil", "Salt", "Pepper", "Baguette"]', '建议搭配：热汤', 0, 0, 15.95, '2025-08-24 06:13:00.945', '南京', 'Android 14 Pixel', '2025-08-24 06:13:00.945', '2025-08-31 18:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000070, 2000003, 'Slow-roast lamb with cinnamon, fennel & citrus', 'https://www.themealdb.com/images/media/meals/gr4lo51763791826.jpg', 'https://www.youtube.com/watch?v=4_mbvxabtJc', 'step 1 Put the lamb into a large food bag with all the juice and marinate overnight. step 2 The next day, take the lamb out of the fridge 1 hr before you want to cook it. Heat oven to 220C/200C fan/gas 7. Take the lamb out of the marinade (reserve remaining marinade) and pat dry. Rub with half the oil and roast for 15-20 mins until browned. Remove lamb and reduce oven to 160C/140C fan/gas 3. step 3 Mix the zests, remaining oil, honey, spices and garlic with plenty of seasoning. Lay a large sheet of baking parchment on a large sheet of foil. Sit the lamb leg on top, rub all over with the paste and pull up the sides of the foil. Drizzle marinade into base, and scrunch foil to seal. step 4 Roast for 4 hrs, until very tender. Rest, still wrapped, for 30 mins. Unwrap and serve with juices.', 1, NULL, 5, 240, 544, 10.8, 14.16, 22.61, 3.7, 120, 5, 5, 0, 0, 0, 2, '["Turkish", "Lamb", "Lamb Leg", "Lemon", "Olive Oil", "Clear Honey", "Cinnamon", "Fennel Seeds"]', '建议搭配：清爽沙拉', 0, 0, 0.0, '2025-05-31 10:13:00.945', '广州', 'Windows Web', '2025-05-31 10:13:00.945', '2025-06-02 11:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000071, 2000004, 'Dundee cake', 'https://www.themealdb.com/images/media/meals/wxyvqq1511723401.jpg', 'https://www.youtube.com/watch?v=4hEXsfpeMQE', 'Put the almonds into a small bowl and pour over boiling water to just cover. Leave for 5 mins then drain in a sieve and leave to dry. Preheat the oven to 180C/160 C fan/Gas Mark 4. Line a deep loose-based 20cm cake tin with baking parchment. Put the butter in a large bowl and beat well until soft. Add the sugar and beat until light and fluffy. Stir in the orange zest and apricot jam. Sieve together the flour and baking powder. Add the eggs to the creamed butter and sugar, a little at a time, beating well between each addition. If the mixture starts to curdle, stir in a little flour. Add the remaining flour and ground almonds and mix well. Mix in the milk and then add the dried fruit and cherries and mix gently together. Spoon the mixture into the prepared tin and spread level using the bac', 2, NULL, 5, 240, 214, 9.63, 0.0, 88.39, 4.6, 240, 16, 0, 2, 0, 0, 2, '["heavy", "Nutty", "Fruity", "British", "Dessert", "Almonds", "Butter", "Muscovado Sugar", "Orange", "Apricot Jam", "Plain Flour"]', '建议搭配：水果', 1, 0, 5.94, '2025-07-11 15:13:00.945', '北京', 'iPad', '2025-07-11 15:13:00.945', '2025-07-12 02:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000072, 2000003, 'Tuna Nicoise', 'https://www.themealdb.com/images/media/meals/yypwwq1511304979.jpg', 'https://www.youtube.com/watch?v=3_UAxkx0u6U', 'Heat oven to 200C/fan 180C/gas 6. Toss the potatoes with 2 tsp oil and some seasoning. Tip onto a large baking tray, then roast for 20 mins, stirring halfway, until crisp, golden and cooked through. Meanwhile, put eggs in a small pan of water, bring to the boil, then simmer for 8-10 mins, depending on how you like them cooked. Plunge into a bowl of cold water to cool for a few mins. Peel away the shells, then cut into halves. In a large salad bowl, whisk together the remaining oil, red wine vinegar, capers and chopped tomatoes. Season, tip in the onion, spinach, tuna and potatoes, then gently toss together. Top with the eggs, then serve straight away.', 1, NULL, 3, 157, 317, 8.84, 29.49, 58.88, 3.2, 5880, 758, 17, 11, 44, 9, 2, '["French", "Seafood", "Potatoes", "Olive Oil", "Eggs", "Red Wine Vinegar", "Capers", "Sunflower Oil"]', '建议搭配：水果', 0, 0, 5.86, '2026-01-14 01:13:00.945', '重庆', 'HarmonyOS', '2026-01-14 01:13:00.945', '2026-01-23 22:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000073, 2000001, 'Chicken Karaage', 'https://www.themealdb.com/images/media/meals/tyywsw1505930373.jpg', 'https://www.youtube.com/watch?v=XivddFddthc', 'Add the ginger, garlic, soy sauce, sake and sugar to a bowl and whisk to combine. Add the chicken, then stir to coat evenly. Cover and refrigerate for at least 1 hour. Add 1 inch of vegetable oil to a heavy bottomed pot and heat until the oil reaches 360 degrees F. Line a wire rack with 2 sheets of paper towels and get your tongs out. Put the potato starch in a bowl Add a handful of chicken to the potato starch and toss to coat each piece evenly. Fry the karaage in batches until the exterior is a medium brown and the chicken is cooked through. Transfer the fried chicken to the paper towel lined rack. If you want the karaage to stay crispy longer, you can fry the chicken a second time, until it''s a darker color after it''s cooled off once. Serve with lemon wedges.', 1, NULL, 3, 161, 492, 18.29, 23.93, 76.53, 4.1, 240, 18, 1, 2, 2, 0, 2, '["Japanese", "Chicken", "Ginger", "Garlic", "Soy sauce", "Sake", "Granulated sugar"]', '建议搭配：热汤', 0, 1, 10.72, '2025-12-27 15:13:00.945', '广州', 'Android 14 Pixel', '2025-12-27 15:13:00.945', '2026-01-01 19:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000074, 2000002, 'Clam, chorizo & white bean stew', 'https://www.themealdb.com/images/media/meals/92wbmf1763252334.jpg', 'https://www.youtube.com/watch?v=IoRuT7TxDAo', 'step 1 Fry the chorizo in a large frying pan with a lid, over a medium heat until it is starting to crisp up and release its oil. Add the onion and cook for 5 mins until starting to soften. Then add the garlic and finely chopped parsley, and fry for 1 min more. step 2 Pour on the stock and tomatoes. Bring to the boil, reduce the heat, then add the beans and sherry vinegar. Simmer for 10 mins until the liquid is slightly reduced. step 3 Scatter over the clams, cover with the lid and steam for 2-4 mins, shaking the pan occasionally until the clams are open. Have a little taste before seasoning, as the clams can be quite salty. Then scatter over the chopped parsley. Eat with lots of crusty bread.', 1, NULL, 4, 171, 473, 70.4, 1.55, 88.54, 3.9, 360, 27, 4, 4, 2, 0, 2, '["Spanish", "Seafood", "Chorizo", "Onion", "Garlic Clove", "Parsley", "Vegetable Stock", "Tinned Tomatos"]', '建议搭配：清爽沙拉', 0, 0, 0.11, '2025-07-30 01:13:00.945', '苏州', 'Android 14 Pixel', '2025-07-30 01:13:00.945', '2025-07-30 15:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000075, 2000002, 'Chivito sandwich', 'https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg', 'https://www.youtube.com/watch?v=tX3fN9AG_ik', 'For the brioche buns heat the milk with the butter and molasses until the butter has melted. Add the cold water and egg to this mix. 2 In a large bowl place flour, salt and yeast and mix. Then add the milk and water mix and stir with a wooden spoon until combined. You don''t have to knead the dough, it is perfectly fine to do this by hand with a wooden spoon, this doesn''t need to be very thorough. Cover with a damp towel and stick in the fridge overnight. 3 The next morning knead dough on a generously floured surface for a little and cut into eight equal pieces. Shape these into balls and place on a baking sheet lined with parchment paper. Cover again with damp towel and let rise for about an hour or until double in size. 4 Heat oven to 220 degrees Celsius. Brush the buns with either milk, ', 1, NULL, 5, 178, 282, 37.31, 4.68, 54.16, 4.2, 5880, 520, 56, 49, 22, 17, 2, '["Uruguayan", "Beef", "Milk", "Butter", "Molasses", "Water", "Egg", "Bread Flour"]', '建议搭配：清爽沙拉', 0, 0, 0.0, '2025-08-09 01:13:00.945', '成都', 'Android Tablet', '2025-08-09 01:13:00.945', '2025-08-09 21:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000076, 2000001, 'French Omelette', 'https://www.themealdb.com/images/media/meals/yvpuuy1511797244.jpg', 'https://www.youtube.com/watch?v=qXPhVYpQLPA', 'Get everything ready. Warm a 20cm (measured across the top) non-stick frying pan on a medium heat. Crack the eggs into a bowl and beat them with a fork so they break up and mix, but not as completely as you would for scrambled egg. With the heat on medium-hot, drop one knob of butter into the pan. It should bubble and sizzle, but not brown. Season the eggs with the Parmesan and a little salt and pepper, and pour into the pan. Let the eggs bubble slightly for a couple of seconds, then take a wooden fork or spatula and gently draw the mixture in from the sides of the pan a few times, so it gathers in folds in the centre. Leave for a few seconds, then stir again to lightly combine uncooked egg with cooked. Leave briefly again, and when partly cooked, stir a bit faster, stopping while there’s ', 1, NULL, 5, 240, 661, 39.66, 30.15, 56.71, 4.0, 120, 9, 0, 1, 1, 0, 2, '["Egg", "French", "Miscellaneous", "Eggs", "Butter", "Parmesan", "Tarragon Leaves", "Parsley", "Chives"]', '建议搭配：气泡水', 0, 1, 6.57, '2025-05-03 18:13:00.945', '上海', 'iPad', '2025-05-03 18:13:00.945', '2025-05-07 08:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000077, 2000000, 'Tamiya', 'https://www.themealdb.com/images/media/meals/n3xxd91598732796.jpg', 'https://www.youtube.com/watch?v=mulqW-J3Yy4', 'oak the beans in water to cover overnight.Drain. If skinless beans are unavailable, rub to loosen the skins, then discard the skins. Pat the beans dry with a towel. Grind the beans in a food mill or meat grinder.If neither appliance is available, process them in a food processor but only until the beans form a paste. (If blended too smoothly, the batter tends to fall apart during cooking.) Add the scallions, garlic, cilantro, cumin, baking powder, cayenne, salt, pepper, and coriander, if using. Refrigerate for at least 30 minutes. Shape the bean mixture into 1-inch balls.Flatten slightly and coat with flour. Heat at least 1½-inches of oil over medium heat to 365 degrees. Fry the patties in batches, turning once, until golden brown on all sides, about 5 minutes.Remove with a wire mesh skimm', 1, NULL, 3, 122, 266, 43.94, 0.0, 23.32, 4.3, 360, 17, 6, 5, 1, 0, 2, '["Egyptian", "Vegetarian", "Broad Beans", "Spring Onions", "Garlic Clove", "Parsley", "Cumin", "Baking Powder"]', '建议搭配：热汤', 1, 0, 4.88, '2025-04-17 00:13:00.945', '广州', 'Windows Web', '2025-04-17 00:13:00.945', '2025-04-22 16:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000078, 2000004, 'Mee goreng mamak', 'https://www.themealdb.com/images/media/meals/xquakq1619787532.jpg', 'https://www.youtube.com/watch?v=pOJEmDBgtSk', 'Heat oil in a pan at medium heat. Then, add peanuts, dried chilies, dried shrimps and dhal. Fry the aromatics until fragrant. Remove from pan and leave aside. Blend fried ingredients with tamarind paste and water until fine. Then, sauté the blended ingredients in oil heated over low heat. Continue cooking until the oil separates from the paste and turns a darker shade. Skin and cut potatoes into small chunks and boil them in a pot of water until knife-tender. Once ready, remove them from the pot and leave aside. Discard water. Slice onion and fried tofu, mince garlic, cut some cabbage and Chinese flowering cabbage (choi sam). Prepare prawn fritters and cut them. Boil noodles to soften them if bought dried. Also mix black soy sauce with water. To fry one portion of mee goreng mamak, heat oi', 1, NULL, 5, 240, 886, 14.64, 42.26, 104.91, 4.2, 120, 5, 6, 0, 1, 0, 2, '["Malaysian", "Seafood", "Peanuts", "Chilli", "Prawns", "Oil", "Water", "Tamarind Paste"]', '建议搭配：热汤', 0, 0, 0.0, '2025-10-03 04:13:00.945', '武汉', 'Android Tablet', '2025-10-03 04:13:00.945', '2025-10-06 06:13:00.945', 0, 1);
INSERT INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version) VALUES (3000079, 2000001, 'Pierogi (Polish Dumplings)', 'https://www.themealdb.com/images/media/meals/45xxr21593348847.jpg', 'https://www.youtube.com/watch?v=lyqDmUroZrI', 'To prepare the sauerkraut filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Add the drained sauerkraut and cook for an additional 5 minutes. Season to taste with salt and pepper, then remove to a plate to cool. For the mashed potato filling, melt the butter in a skillet over medium heat. Stir in the onion, and cook until translucent, about 5 minutes. Stir into the mashed potatoes, and season with salt and white pepper. To make the dough, beat together the eggs and sour cream until smooth. Sift together the flour, salt, and baking powder; stir into the sour cream mixture until dough comes together. Knead the dough on a lightly floured surface until firm and smooth. Divide the dough in half, then roll out one half to 1/8 i', 1, NULL, 5, 240, 703, 47.42, 22.76, 0.0, 4.3, 480, 38, 24, 4, 0, 0, 2, '["Polish", "Side", "Butter", "Chopped Onion", "Sauerkraut", "Potatoes"]', '建议搭配：清爽沙拉', 0, 0, 4.02, '2025-05-26 15:13:00.945', '广州', 'Mac Safari', '2025-05-26 15:13:00.945', '2025-06-05 06:13:00.945', 0, 1);
