INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300000007, 3000000, 7, '(If you haven’t got a steamer, put the parcel on a heatproof plate over a pan of gently simmering water, cover with a lid and steam.)', NULL, NULL, 9, 0, NULL, '2025-11-29 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300000101, 3000001, 1, 'Pound the garlic with sea salt in a pestle and mortar (or use a small food processor), until the garlic forms a paste', 'https://www.themealdb.com/images/media/meals/rjhf741585564676.jpg', 'https://www.youtube.com/watch?v=krR4rhjR75Y', 10, 1, NULL, '2025-12-01 15:13:00.945');
