INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001502, 3000015, 2, 'To a large bowl, add flour, 1 teaspoon salt, and turmeric and mix thoroughly.', NULL, NULL, 11, 0, NULL, '2025-09-25 03:13:00.945');
