INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001505, 3000015, 5, 'Keep adding ice water 2 to 3 tablespoons at a time until the mixture forms a dough.', NULL, NULL, 5, 0, NULL, '2025-09-25 03:13:00.945');
