INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001701, 3000017, 1, 'step 1', 'https://www.themealdb.com/images/media/meals/lmc6r51764365554.jpg', 'https://www.youtube.com/watch?v=bP7m7xx0GpM', 8, 1, NULL, '2025-05-19 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001702, 3000017, 2, 'Tip the flours, yeast and salt into a bowl', NULL, NULL, 15, 0, NULL, '2025-05-19 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001703, 3000017, 3, 'In a jug, mix the honey with 250ml warm water, pour the liquid into the bowl and mix to form a dough', NULL, NULL, 6, 0, NULL, '2025-05-19 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001704, 3000017, 4, 'Rye flour can be quite dry and absorbs lots of water, if the dough looks too dry add more warm water until you have a soft dough Tip out onto your work surface and knead for 10 mins until smooth', NULL, NULL, 6, 1, NULL, '2025-05-19 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001705, 3000017, 5, 'Rye contains less gluten than white flour so the dough will not feel as springy as a conventional white loaf.', NULL, NULL, 7, 0, NULL, '2025-05-19 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001706, 3000017, 6, 'step 2', NULL, NULL, 4, 0, NULL, '2025-05-19 00:13:00.945');
