INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001708, 3000017, 8, 'Dust a 2lb/900g loaf tin with flour.', NULL, NULL, 10, 1, NULL, '2025-05-19 00:13:00.945');
