INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300001711, 3000017, 11, 'If using caraway seeds work these in to the dough', NULL, NULL, 17, 0, NULL, '2025-05-19 00:13:00.945');
