INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002601, 3000026, 1, 'step 1', 'https://www.themealdb.com/images/media/meals/pvfkz61761595976.jpg', 'https://www.youtube.com/watch?v=r1lnsOTNjws', 8, 1, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002602, 3000026, 2, 'Heat oven to 160C/140C fan/gas 3', NULL, NULL, 5, 0, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002603, 3000026, 3, 'Soften the celery, onion, carrots, bay and 1 thyme sprig in a casserole with 1 tbsp oil and the butter for 10 mins', NULL, NULL, 1, 0, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002604, 3000026, 4, 'Stir in the flour, followed by the purée, Worcestershire sauce and stock cubes.', NULL, NULL, 1, 1, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002605, 3000026, 5, 'step 2', NULL, NULL, 1, 0, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002606, 3000026, 6, 'Gradually stir in 600ml hot water, then tip in the beef and bring to a gentle simmer', NULL, NULL, 4, 0, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002607, 3000026, 7, 'Cover and cook in the oven for 2 hrs 30 mins, then uncover and cook for 30 mins -1 hr more until the meat is really tender and sauce thickened.', NULL, NULL, 3, 0, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002608, 3000026, 8, 'step 3', NULL, NULL, 7, 1, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002609, 3000026, 9, 'Meanwhile, cook potatoes in a pan of boiling water until they’re not done but about ¾ of the way there.', NULL, NULL, 9, 0, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002610, 3000026, 10, 'step 4', NULL, NULL, 5, 0, NULL, '2025-08-03 20:13:00.945');
