INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002616, 3000026, 16, 'Increase oven to 200C/180C fan/gas 6 and bake for 30-40 mins until golden and crispy, and sauce bubbling if the dish went in cold', NULL, NULL, 8, 1, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002617, 3000026, 17, 'Serve with peas.', NULL, NULL, 4, 0, NULL, '2025-08-03 20:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002701, 3000027, 1, 'Season shrimp with 1 Tablespoon of curry powder and all-purpose seasoning and set aside for about 10 minutes while you prepare the other ingredients like chopping your onions, peppers, and garlic.', 'https://www.themealdb.com/images/media/meals/n7h5zs1765318909.jpg', 'https://www.youtube.com/watch?v=Lnaj4duQ7hs', 8, 1, NULL, '2025-07-28 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002702, 3000027, 2, 'Heat 2 Tablespoons of olive oil in a large skillet over medium heat', NULL, NULL, 1, 0, NULL, '2025-07-28 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002703, 3000027, 3, 'Add sliced yellow onion, red bell pepper, green bell pepper, scotch bonnet pepper, if using, and chopped garlic and stir for 5 minutes, until peppers are slightly softened.', NULL, NULL, 8, 0, NULL, '2025-07-28 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002704, 3000027, 4, 'Add 1.5 Tablespoons of curry powder to the skillet and stir for an additional minute.', NULL, NULL, 9, 1, NULL, '2025-07-28 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002705, 3000027, 5, 'Then add coconut milk, seasoned shrimp, ketchup, and thyme, making sure the shrimp is covered in the sauce.', NULL, NULL, 1, 0, NULL, '2025-07-28 11:13:00.945');
