INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002707, 3000027, 7, 'This should take about 5-6 minutes', NULL, NULL, 14, 0, NULL, '2025-07-28 11:13:00.945');
