INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300002801, 3000028, 1, 'STEP 1', 'https://www.themealdb.com/images/media/meals/lpd4wy1614347943.jpg', 'https://www.youtube.com/watch?v=JYtMjKa6cdY', 4, 1, NULL, '2025-07-05 18:13:00.945');
