INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003008, 3000030, 8, 'Yellow egg cream', NULL, NULL, 9, 1, NULL, '2026-02-01 04:13:00.945');
