INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003101, 3000031, 1, 'Heat the 2 tablespoons of oil in a large skillet or pot over medium heat until shimmering', 'https://www.themealdb.com/images/media/meals/60o82j1762341177.jpg', 'https://www.youtube.com/watch?v=02hHtPDAxOs', 5, 1, NULL, '2025-06-22 10:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003102, 3000031, 2, 'Add the onions and cook, stirring occasionally, until softened, 5 to 7 minutes.', NULL, NULL, 11, 0, NULL, '2025-06-22 10:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003103, 3000031, 3, 'Add the shredded kale to the onions and mix well', NULL, NULL, 15, 0, NULL, '2025-06-22 10:13:00.945');
