INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003107, 3000031, 7, 'The cream will thicken slightly, making for a deliciously rich creamed kale and onions', NULL, NULL, 1, 0, NULL, '2025-06-22 10:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003108, 3000031, 8, 'Serve it up with your favorite Kenyan stew, and a side of ugali!', NULL, NULL, 9, 1, NULL, '2025-06-22 10:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003201, 3000032, 1, 'For the biscuits, preheat the oven to 200C/180C (fan)/Gas 6 and line two large baking trays with baking parchment', 'https://www.themealdb.com/images/media/meals/rpvptu1511641092.jpg', 'https://www.youtube.com/watch?v=kniRGjDLFrQ', 9, 1, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003202, 3000032, 2, 'Scatter the nuts over a baking tray and roast in the oven for 6-8 minutes, or until golden-brown', NULL, NULL, 7, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003203, 3000032, 3, 'Watch them carefully so that they don’t have a chance to burn', NULL, NULL, 11, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003204, 3000032, 4, 'Remove from the oven, tip onto a board and leave to cool.', NULL, NULL, 8, 1, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003205, 3000032, 5, 'Put the butter and sugar in a large bowl and beat with a wooden spoon until light and creamy', NULL, NULL, 14, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003206, 3000032, 6, 'Roughly chop the cooled nuts and add to the creamed butter and sugar, along with the lemon zest, flour and baking powder', NULL, NULL, 14, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003207, 3000032, 7, 'Stir well until the mixture comes together and forms a ball – you may need to use your hands.', NULL, NULL, 13, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003208, 3000032, 8, 'Divide the biscuit dough into 24 even pieces and roll into small balls', NULL, NULL, 12, 1, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003209, 3000032, 9, 'Place the balls the prepared baking trays, spaced well apart to allow for spreading.', NULL, NULL, 5, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003210, 3000032, 10, 'Press the biscuits to flatten to around 1cm/½in thick', NULL, NULL, 7, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003211, 3000032, 11, 'Bake the biscuits, one tray at a time, for 12 minutes or until very pale golden-brown', NULL, NULL, 9, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003212, 3000032, 12, 'Leave to cool on the trays', NULL, NULL, 9, 1, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003213, 3000032, 13, 'They will be very soft when you take them out of the oven, but will crisp as they cool.', NULL, NULL, 10, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003214, 3000032, 14, 'Store in an airtight tin and eat within five days.', NULL, NULL, 11, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003215, 3000032, 15, 'For the fool, rinse the blackberries in a colander to wash away any dust or dirt', NULL, NULL, 8, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003216, 3000032, 16, 'Put the blackberries in a non-stick saucepan and sprinkle over the caster sugar.', NULL, NULL, 10, 1, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003217, 3000032, 17, 'Stir in the lemon juice and heat gently for two minutes, or until the blackberries begin to soften and release their juices', NULL, NULL, 10, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003218, 3000032, 18, 'Remove and reserve 12 blackberries for decoration and continue cooking the rest.', NULL, NULL, 8, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003219, 3000032, 19, 'Simmer the blackberries very gently for 15 minutes, stirring regularly until very soft and squidgy', NULL, NULL, 8, 0, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003220, 3000032, 20, 'Remove from the heat and press the berries and juice through a sieve over a bowl, using the bottom of a ladle to help you extract as much of the purée as possible', NULL, NULL, 11, 1, NULL, '2025-12-26 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003301, 3000033, 1, 'step 1', 'https://www.themealdb.com/images/media/meals/snmtd61763426568.jpg', 'https://www.youtube.com/watch?v=cxryD8ZHCdQ', 6, 1, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003302, 3000033, 2, 'Heat the oil in a large saucepan or flameproof casserole', NULL, NULL, 9, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003303, 3000033, 3, 'Add the spring onions and coriander stalks and cook for 1 min', NULL, NULL, 2, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003304, 3000033, 4, 'Add the pork slices and cook for 5 mins until starting to brown.', NULL, NULL, 4, 1, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003305, 3000033, 5, 'step 2', NULL, NULL, 2, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003306, 3000033, 6, 'Stir in the curry paste and peanut butter', NULL, NULL, 8, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003307, 3000033, 7, 'After 30 secs, add the sugar, soy and coconut milk, plus ½ can of water', NULL, NULL, 8, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003308, 3000033, 8, 'Mix well, put a lid on and leave to simmer for 15 mins, stirring occasionally.', NULL, NULL, 8, 1, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003309, 3000033, 9, 'step 3', NULL, NULL, 10, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003310, 3000033, 10, 'Remove the lid, add the baby corn and increase the heat', NULL, NULL, 7, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003311, 3000033, 11, 'Bubble for 3 mins until the corn is cooked and the sauce has thickened a little', NULL, NULL, 13, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003312, 3000033, 12, 'Stir in the lime juice and check the seasoning', NULL, NULL, 5, 1, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003313, 3000033, 13, 'Can now be frozen for up to 2 months', NULL, NULL, 10, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003314, 3000033, 14, 'To cook from frozen: thoroughly defrost, then heat in a pan on the hob until curry is hot all the way through', NULL, NULL, 1, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003315, 3000033, 15, 'Serve scattered with the coriander leaves and rice.', NULL, NULL, 12, 0, NULL, '2026-01-12 19:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003401, 3000034, 1, 'step 1', 'https://www.themealdb.com/images/media/meals/8c8m4q1763791156.jpg', 'https://www.youtube.com/watch?v=JOXBWo37wWU', 6, 1, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003402, 3000034, 2, 'Heat grill to very hot', NULL, NULL, 7, 0, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003403, 3000034, 3, 'Slice the aubergines in half lengthways, then grill for 25 mins, turning occasionally, until soft – the skin will remain firm, but the flesh will soften', NULL, NULL, 8, 0, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003404, 3000034, 4, 'Lift the aubergines off the grill and leave until cool enough to handle.', NULL, NULL, 16, 1, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003405, 3000034, 5, 'step 2', NULL, NULL, 3, 0, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003406, 3000034, 6, 'Using a sharp knife, score the grilled flesh and scoop out the flesh with a spoon', NULL, NULL, 1, 0, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003407, 3000034, 7, 'Tip into a bowl and mash with a fork until you get a thick pulp', NULL, NULL, 7, 0, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003408, 3000034, 8, 'Beat in the lemon juice and garlic', NULL, NULL, 4, 1, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003409, 3000034, 9, 'Add the yogurt and dill, and season', NULL, NULL, 10, 0, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003410, 3000034, 10, 'Serve while still warm.', NULL, NULL, 14, 0, NULL, '2025-07-07 21:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003501, 3000035, 1, 'Heat oven to 180C/160C fan/gas 4 and line the base and sides of a 20cm square tin with baking parchment (the easiest way is to cross 2 x 20cm-long strips over the base)', 'https://www.themealdb.com/images/media/meals/ywwrsp1511720277.jpg', 'https://www.youtube.com/watch?v=aB41Q7kDZQ0', 4, 1, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003502, 3000035, 2, 'To make the almond sponge, put the butter, sugar, flour, ground almonds, baking powder, eggs, vanilla and almond extract in a large bowl', NULL, NULL, 10, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003503, 3000035, 3, 'Beat with an electric whisk until the mix comes together smoothly', NULL, NULL, 7, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003504, 3000035, 4, 'Scrape into the tin, spreading to the corners, and bake for 25-30 mins – when you poke in a skewer, it should come out clean', NULL, NULL, 6, 1, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003505, 3000035, 5, 'Cool in the tin for 10 mins, then transfer to a wire rack to finish cooling while you make the second sponge.', NULL, NULL, 11, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003506, 3000035, 6, 'For the pink sponge, line the tin as above', NULL, NULL, 12, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003507, 3000035, 7, 'Mix all the ingredients together as above, but don’t add the almond extract', NULL, NULL, 9, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003508, 3000035, 8, 'Fold in some pink food colouring', NULL, NULL, 15, 1, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003509, 3000035, 9, 'Then scrape it all into the tin and bake as before', NULL, NULL, 5, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003510, 3000035, 10, 'To assemble, heat the jam in a small pan until runny, then sieve', NULL, NULL, 5, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003511, 3000035, 11, 'Barely trim two opposite edges from the almond sponge, then well trim a third edge', NULL, NULL, 8, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003512, 3000035, 12, 'Roughly measure the height of the sponge, then cutting from the well-trimmed edge, use a ruler to help you cut 4 slices each the same width as the sponge height', NULL, NULL, 9, 1, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003513, 3000035, 13, 'Discard or nibble leftover sponge', NULL, NULL, 2, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003514, 3000035, 14, 'Repeat with pink cake.', NULL, NULL, 2, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003515, 3000035, 15, 'Take 2 x almond slices and 2 x pink slices and trim so they are all the same length', NULL, NULL, 4, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003516, 3000035, 16, 'Roll out one marzipan block on a surface lightly dusted with icing sugar to just over 20cm wide, then keep rolling lengthways until the marzipan is roughly 0.5cm thick', NULL, NULL, 6, 1, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003517, 3000035, 17, 'Brush with apricot jam, then lay a pink and an almond slice side by side at one end of the marzipan, brushing jam in between to stick sponges, and leaving 4cm clear marzipan at the end', NULL, NULL, 3, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003518, 3000035, 18, 'Brush more jam on top of the sponges, then sandwich remaining 2 slices on top, alternating colours to give a checkerboard effect', NULL, NULL, 8, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003519, 3000035, 19, 'Trim the marzipan to the length of the cakes.', NULL, NULL, 14, 0, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003520, 3000035, 20, 'Carefully lift up the marzipan and smooth over the cake with your hands, but leave a small marzipan fold along the bottom edge before you stick it to the first side', NULL, NULL, 15, 1, NULL, '2025-07-02 14:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003601, 3000036, 1, 'Melt 50g butter in a large saucepan (about 20cm across), add 1 finely chopped medium onion and cook gently over a medium heat for 5 minutes, until softened but not browned.', 'https://www.themealdb.com/images/media/meals/1550441275.jpg', 'https://www.youtube.com/watch?v=QqdzDCWS4gQ', 8, 1, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003602, 3000036, 2, 'Stir in 3 split cardamom pods, ¼ tsp turmeric, 1 small cinnamon stick and 2 bay leaves, then cook for 1 minute.', NULL, NULL, 9, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003603, 3000036, 3, 'Tip in 450g basmati rice and stir until it is all well coated in the spicy butter.', NULL, NULL, 10, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003604, 3000036, 4, 'Pour in 1 litre chicken or fish stock, add ½ teaspoon salt and bring to the boil, stir once to release any rice from the bottom of the pan', NULL, NULL, 12, 1, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003605, 3000036, 5, 'Cover with a close-fitting lid, reduce the heat to low and leave to cook very gently for 12 minutes.', NULL, NULL, 5, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003606, 3000036, 6, 'Meanwhile, bring some water to the boil in a large shallow pan', NULL, NULL, 2, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003607, 3000036, 7, 'Add 750g un-dyed smoked haddock fillet and simmer for 4 minutes, until the fish is just cooked', NULL, NULL, 9, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003608, 3000036, 8, 'Lift it out onto a plate and leave until cool enough to handle.', NULL, NULL, 12, 1, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003609, 3000036, 9, 'Hard-boil 3 eggs for 8 minutes.', NULL, NULL, 7, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003610, 3000036, 10, 'Flake the fish, discarding any skin and bones', NULL, NULL, 8, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003611, 3000036, 11, 'Drain the eggs, cool slightly, then peel and chop.', NULL, NULL, 9, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003612, 3000036, 12, 'Uncover the rice and remove the bay leaves, cinnamon stick and cardamom pods if you wish to', NULL, NULL, 7, 1, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003613, 3000036, 13, 'Gently fork in the fish and the chopped eggs, cover again and return to the heat for 2-3 minutes, or until the fish has heated through.', NULL, NULL, 5, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003614, 3000036, 14, 'Gently stir in almost all the 3 tbsp chopped fresh parsley, and season with a little salt and black pepper to taste', NULL, NULL, 11, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003615, 3000036, 15, 'Serve scattered with the remaining parsley and garnished with 1 lemon, cut into wedges.', NULL, NULL, 9, 0, NULL, '2025-08-19 05:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003701, 3000037, 1, 'step 1', 'https://www.themealdb.com/images/media/meals/3m8yae1763257951.jpg', 'https://www.youtube.com/watch?v=kzLaw6PG2UY', 10, 1, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003702, 3000037, 2, 'Soak the potatoes in just-boiled water for 30 mins, then drain and leave to air-dry for 5 mins', NULL, NULL, 7, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003703, 3000037, 3, 'Heat the air fryer to 200C', NULL, NULL, 12, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003704, 3000037, 4, 'Tip the potatoes into a bowl and drizzle over 1 tbsp of the oil and add 1/2 tsp each of salt and freshly ground black pepper', NULL, NULL, 13, 1, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003705, 3000037, 5, 'Mix to coat the potatoes all over, then tip into the air fryer basket and cook for 20-30 mins until crisp and golden.', NULL, NULL, 10, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003706, 3000037, 6, 'step 2', NULL, NULL, 5, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003707, 3000037, 7, 'Meanwhile, heat the remaining oil in a small pan over a medium-low heat and fry the onion for 8-10 mins until softened but not golden', NULL, NULL, 2, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003708, 3000037, 8, 'Stir in the garlic and cook for a minute before adding the paprika and cooking for 30 seconds more', NULL, NULL, 8, 1, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003709, 3000037, 9, 'Stir in the tomato purée, cook for 1 min, then tip in the chopped tomatoes', NULL, NULL, 9, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003710, 3000037, 10, 'Cook for 5-10 mins over a medium heat until thickened slightly.', NULL, NULL, 6, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003711, 3000037, 11, 'step 3', NULL, NULL, 7, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003712, 3000037, 12, 'Once the potatoes are cooked, tip out onto a platter and pour over the tomato sauce', NULL, NULL, 8, 1, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003713, 3000037, 13, 'Sprinkle with the basil leaves, then serve.', NULL, NULL, 5, 0, NULL, '2025-10-28 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003801, 3000038, 1, 'step 1', 'https://www.themealdb.com/images/media/meals/pbzcrx1763765096.jpg', 'https://www.youtube.com/watch?v=WlosNFMCnE4', 3, 1, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003802, 3000038, 2, 'Tip the beef stock along with 500ml of water into a large saucepan', NULL, NULL, 4, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003803, 3000038, 3, 'Sit the onion and ginger in a frying pan over a high heat and char on all sides, around 3-5 mins (you can also do this under your grill)', NULL, NULL, 12, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003804, 3000038, 4, 'Once charred, add to the beef stock', NULL, NULL, 12, 1, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003805, 3000038, 5, 'In the same pan, toast the spices for 2-3 mins and once they begin to smell fragrant, add them to the beef stock as well', NULL, NULL, 9, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003806, 3000038, 6, 'Bring the stock to the boil, then turn to a simmer and cook for 30mins before straining.', NULL, NULL, 8, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003807, 3000038, 7, 'step 2', NULL, NULL, 12, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003808, 3000038, 8, 'Meanwhile, cut the fat from the steak and wrap in cling film, then put into the freezer for 15 mins – this will make your steak really easy to slice! Slice it thinly, then cover with cling film again and pop into the fridge.', NULL, NULL, 1, 1, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003809, 3000038, 9, 'step 3', NULL, NULL, 11, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003810, 3000038, 10, 'Taste the beef stock and use the palm sugar, fish sauce and soy to season', NULL, NULL, 13, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003811, 3000038, 11, 'Cook the noodles according to package instructions and split between two bowls, topping each with the sliced beef', NULL, NULL, 11, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003812, 3000038, 12, 'Bring the stock to the boil and then pour into the bowls (the heat will cook the beef)', NULL, NULL, 7, 1, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003813, 3000038, 13, 'Top each with the spring onions, chilli slices and herbs', NULL, NULL, 6, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003814, 3000038, 14, 'Serve with the lime wedges to squeeze over.', NULL, NULL, 1, 0, NULL, '2025-11-03 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003901, 3000039, 1, 'In a large cast iron skillet or sauté pan with a lid, heat oil over medium high heat', 'https://www.themealdb.com/images/media/meals/gpz67p1560458984.jpg', 'https://www.youtube.com/watch?v=EHKNu93MSx4', 12, 1, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003902, 3000039, 2, 'Add the onion and sauté for 2-3 minutes, until softened', NULL, NULL, 9, 0, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003903, 3000039, 3, 'Add the peppers and garlic, and sauté for an additional 3-5 minutes', NULL, NULL, 10, 0, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003904, 3000039, 4, 'Add the tomatoes, cumin, paprika, salt, and chili powder', NULL, NULL, 11, 1, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003905, 3000039, 5, 'Mix well and bring the mixture to a simmer', NULL, NULL, 6, 0, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003906, 3000039, 6, 'Reduce the heat to medium low and continue to simmer, uncovered, 10-15 minutes until the mixture has thickened to your desired consistency', NULL, NULL, 7, 0, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003907, 3000039, 7, '(Taste the sauce at this point and adjust for salt and spice, as desired.) Using the back of a spoon, make four craters in the mixture, large enough to hold an egg', NULL, NULL, 9, 0, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003908, 3000039, 8, 'Crack one egg into each of the craters', NULL, NULL, 9, 1, NULL, '2025-06-17 22:13:00.945');
