INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300003910, 3000039, 10, 'Serve immediately with crusty bread or pita.', NULL, NULL, 14, 0, NULL, '2025-06-17 22:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004001, 3000040, 1, 'Cut the aubergines in half lengthways', 'https://www.themealdb.com/images/media/meals/wrpwuu1511786491.jpg', 'https://www.youtube.com/watch?v=BFdQUgAFtGU', 1, 1, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004002, 3000040, 2, 'Place them on the board, cut side down, slice in half lengthways again and then across into 1.5cm chunks', NULL, NULL, 10, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004003, 3000040, 3, 'Cut off the courgettes ends, then across into 1.5cm slices', NULL, NULL, 14, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004004, 3000040, 4, 'Peel the peppers from stalk to bottom', NULL, NULL, 2, 1, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004005, 3000040, 5, 'Hold upright, cut around the stalk, then cut into 3 pieces', NULL, NULL, 9, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004006, 3000040, 6, 'Cut away any membrane, then chop into bite-size chunks.', NULL, NULL, 5, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004007, 3000040, 7, 'Score a small cross on the base of each tomato, then put them into a heatproof bowl', NULL, NULL, 16, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004008, 3000040, 8, 'Pour boiling water over the tomatoes, leave for 20 secs, then remove', NULL, NULL, 9, 1, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004009, 3000040, 9, 'Pour the water away, replace the tomatoes and cover with cold water', NULL, NULL, 4, 0, NULL, '2025-10-24 01:13:00.945');
