INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004012, 3000040, 12, 'Set a sauté pan over medium heat and when hot, pour in 2 tbsp olive oil', NULL, NULL, 11, 1, NULL, '2025-10-24 01:13:00.945');
