INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004017, 3000040, 17, 'Tear up the basil leaves and set aside', NULL, NULL, 8, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004018, 3000040, 18, 'Cook the onion in the pan for 5 mins', NULL, NULL, 8, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004019, 3000040, 19, 'Add the garlic and fry for a further min', NULL, NULL, 6, 0, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004020, 3000040, 20, 'Stir in the vinegar and sugar, then tip in the tomatoes and half the basil', NULL, NULL, 1, 1, NULL, '2025-10-24 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004101, 3000041, 1, 'Make the beef tenderloin marinade by combining soy sauce, vinegar, ginger, garlic, sesame oil, olive oil, sugar, salt, and ground black pepper in a large bowl', 'https://www.themealdb.com/images/media/meals/cgl60b1683206581.jpg', 'https://www.youtube.com/watch?v=jxW3Lj8VjyE', 9, 1, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004102, 3000041, 2, 'Mix well.', NULL, NULL, 6, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004103, 3000041, 3, 'Add the cubed beef tenderloin to the bowl with the beef tenderloin marinade', NULL, NULL, 10, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004104, 3000041, 4, 'Gently toss to coat the beef', NULL, NULL, 9, 1, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004105, 3000041, 5, 'Let it stay for 1 hour.', NULL, NULL, 1, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004106, 3000041, 6, 'Using a metal or bamboo skewer, assemble the beef kebob by skewering the vegetables and marinated beef tenderloin.', NULL, NULL, 7, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004107, 3000041, 7, 'Heat-up the grill and start grilling the beef kebobs for 3 minutes per side', NULL, NULL, 6, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004108, 3000041, 8, 'This will give you a medium beef that is juicy and tender on the inside', NULL, NULL, 10, 1, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004109, 3000041, 9, 'Add more time if you want your beef well done, but it will be less tender.', NULL, NULL, 9, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004110, 3000041, 10, 'Transfer to a serving plate', NULL, NULL, 1, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004111, 3000041, 11, 'Serve with Saffron rice.', NULL, NULL, 9, 0, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004112, 3000041, 12, 'Share and enjoy!', NULL, NULL, 5, 1, NULL, '2026-02-01 02:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004201, 3000042, 1, 'Heat the flat grill plate over a low heat, on top of 2 rings/flames if it fits, and brush sparingly with light olive oil.', 'https://www.themealdb.com/images/media/meals/utxryw1511721587.jpg', 'https://www.youtube.com/watch?v=FXjYU2Ensck', 8, 1, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004202, 3000042, 2, 'Cook the sausages first', NULL, NULL, 8, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004203, 3000042, 3, 'Add the sausages to the hot grill plate/the coolest part if there is one and allow to cook slowly for about 15-20 minutes, turning occasionally, until golden', NULL, NULL, 8, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004204, 3000042, 4, 'After the first 10 minutes, increase the heat to medium before beginning to cook the other ingredients', NULL, NULL, 13, 1, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004205, 3000042, 5, 'If you are struggling for space, completely cook the sausages and keep hot on a plate in the oven.', NULL, NULL, 7, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004206, 3000042, 6, 'Snip a few small cuts into the fatty edge of the bacon', NULL, NULL, 3, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004207, 3000042, 7, 'Place the bacon straight on to the grill plate and fry for 2-4 minutes each side or until your preferred crispiness is reached', NULL, NULL, 13, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004208, 3000042, 8, 'Like the sausages, the cooked bacon can be kept hot on a plate in the oven.', NULL, NULL, 8, 1, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004209, 3000042, 9, 'For the mushrooms, brush away any dirt using a pastry brush and trim the stalk level with the mushroom top', NULL, NULL, 13, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004210, 3000042, 10, 'Season with salt and pepper and drizzle over a little olive oil', NULL, NULL, 6, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004211, 3000042, 11, 'Place stalk-side up on the grill plate and cook for 1-2 minutes before turning and cooking for a further 3-4 minutes', NULL, NULL, 7, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004212, 3000042, 12, 'Avoid moving the mushrooms too much while cooking, as this releases the natural juices, making them soggy.', NULL, NULL, 5, 1, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004213, 3000042, 13, 'For the tomatoes, cut the tomatoes across the centre/or in half lengthways if using plum tomatoes , and with a small, sharp knife remove the green ''eye''', NULL, NULL, 9, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004214, 3000042, 14, 'Season with salt and pepper and drizzle with a little olive oil', NULL, NULL, 2, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004215, 3000042, 15, 'Place cut-side down on the grill plate and cook without moving for 2 minutes', NULL, NULL, 18, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004216, 3000042, 16, 'Gently turn over and season again', NULL, NULL, 1, 1, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004217, 3000042, 17, 'Cook for a further 2-3 minutes until tender but still holding their shape.', NULL, NULL, 11, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004218, 3000042, 18, 'For the black pudding, cut the black pudding into 3-4 slices and remove the skin', NULL, NULL, 7, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004219, 3000042, 19, 'Place on the grill plate and cook for 1½-2 minutes each side until slightly crispy.', NULL, NULL, 1, 0, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004220, 3000042, 20, 'For ''proper'' fried bread it''s best to cook it in a separate pan', NULL, NULL, 9, 1, NULL, '2026-01-11 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004301, 3000043, 1, 'step 1', 'https://www.themealdb.com/images/media/meals/72fgzj1764109947.jpg', 'https://www.youtube.com/watch?v=o0UbzRZw-GQ', 12, 1, NULL, '2025-09-09 08:13:00.945');
