INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300004902, 3000049, 2, 'Use a spoon to push the egg yolk through a fine sieve into the flour.', NULL, NULL, 2, 0, NULL, '2026-01-30 17:13:00.945');
