INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006402, 3000064, 2, 'In a large soup pot, boil the potatoes and the bay leaves in salted water for 20 minutes', NULL, NULL, 13, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006403, 3000064, 3, 'Discard the bay leaves.', NULL, NULL, 4, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006404, 3000064, 4, 'If you''re not using a bag of ready-cut curly kale, wash the bunches thoroughly under cool running water to get rid of all soil—you wouldn''t want that gritty texture in your finished dish', NULL, NULL, 1, 1, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006405, 3000064, 5, 'Trim any coarse stems and discard any brown leaves', NULL, NULL, 5, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006406, 3000064, 6, 'With a sharp knife, cut the curly kale into thin strips.', NULL, NULL, 7, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006407, 3000064, 7, 'Peel and chop the shallots.', NULL, NULL, 9, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006408, 3000064, 8, 'In a frying pan or skillet, melt 1 tbsp', NULL, NULL, 5, 1, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006409, 3000064, 9, 'of butter and saute the shallots for a few minutes before adding the curly kale and 2 tbsp', NULL, NULL, 6, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006410, 3000064, 10, 'of water', NULL, NULL, 5, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006411, 3000064, 11, 'Season and cook for about 10 minutes, or until tender.', NULL, NULL, 11, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006412, 3000064, 12, 'Warm the milk on the stove or in the microwave.', NULL, NULL, 10, 1, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006413, 3000064, 13, 'Drain, shake and dry the potatoes with kitchen towels before mashing with a potato masher or ricer', NULL, NULL, 11, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006414, 3000064, 14, 'Working quickly, add the warm milk and the remaining butter', NULL, NULL, 9, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006415, 3000064, 15, 'Season to taste with nutmeg, salt, and pepper.', NULL, NULL, 13, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006416, 3000064, 16, 'Mix the cooked curly kale through the cooked mashed potato mixture.', NULL, NULL, 8, 1, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006417, 3000064, 17, 'Top with slices of the smoked sausage and serve hot with your favorite mustard or gravy.', NULL, NULL, 1, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006418, 3000064, 18, 'Serve and enjoy!', NULL, NULL, 6, 0, NULL, '2025-05-07 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006501, 3000065, 1, 'This is one recipe a lot of people have requested and I have tried to make it as simple as possible and I hope it will work for you', 'https://www.themealdb.com/images/media/meals/thazgm1555350962.jpg', '', 11, 1, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006502, 3000065, 2, 'Make sure you use the right flour which is basically one with raising agents', NULL, NULL, 7, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006503, 3000065, 3, 'Adjust the amount of sugar to your taste and try using different flavours to have variety whenever you have them.', NULL, NULL, 13, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006504, 3000065, 4, 'You can use Coconut milk instead of regular milk, you can also add desiccated coconut to the dry flour or other spices like powdered cloves or cinnamon.', NULL, NULL, 5, 1, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006505, 3000065, 5, 'For “healthy looking” mandazis do not roll the dough too thin before frying and use the procedure I have indicated above.', NULL, NULL, 7, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006506, 3000065, 6, 'Mix the flour,cinnamon and sugar in a suitable bowl.', NULL, NULL, 8, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006507, 3000065, 7, 'In a separate bowl whisk the egg into the milk', NULL, NULL, 14, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006508, 3000065, 8, 'Make a well at the centre of the flour and add the milk and egg mixture and slowly mix to form a dough.', NULL, NULL, 4, 1, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006509, 3000065, 9, 'Knead the dough for 3-4 minutes or until it stops sticking to the sides of the bowl and you have a smooth surface.', NULL, NULL, 4, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006510, 3000065, 10, 'Cover the dough with a damp cloth and allow to rest for 15 minutes.', NULL, NULL, 14, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006511, 3000065, 11, 'Roll the dough on a lightly floured surface into a 1cm thick piece.', NULL, NULL, 6, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006512, 3000065, 12, 'Using a sharp small knife, cut the dough into the desired size setting aside ready for deep frying.', NULL, NULL, 10, 1, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006513, 3000065, 13, 'Heat your oil in a suitable pot and gently dip the mandazi pieces to cook until light brown on the first side then turn to cook on the second side.', NULL, NULL, 10, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006514, 3000065, 14, 'Serve them warm or cold', NULL, NULL, 6, 0, NULL, '2025-12-16 16:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006601, 3000066, 1, 'Place a steamer insert into a saucepan, and fill with 1 1/2 cups of water, or just below the bottom of the steamer', 'https://www.themealdb.com/images/media/meals/o2cd4r1764113576.jpg', 'https://www.youtube.com/watch?v=mF2ND56szUQ', 10, 1, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006602, 3000066, 2, 'Cover, and bring the water to a boil over high heat', NULL, NULL, 1, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006603, 3000066, 3, 'Add the sliced carrots, reduce the heat to medium, and cover the pan again', NULL, NULL, 6, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006604, 3000066, 4, 'Steam until tender but not mushy, 4 to 6 minutes depending on the thickness of the slices', NULL, NULL, 9, 1, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006605, 3000066, 5, 'Reserve 1/2 cup of the cooking liquid.', NULL, NULL, 5, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006606, 3000066, 6, 'Heat the olive oil in a skillet over medium heat', NULL, NULL, 3, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006607, 3000066, 7, 'Reduce the heat to low and stir in the salt, pepper, cinnamon, cumin, garlic, and thyme', NULL, NULL, 14, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006608, 3000066, 8, 'Cook the spices and garlic, stirring frequently, until fragrant, about 10 minutes', NULL, NULL, 9, 1, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006609, 3000066, 9, 'Add the 1/2 cup reserved cooking liquid and the bay leaf, cover, and simmer for 20 minutes.', NULL, NULL, 8, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006610, 3000066, 10, 'Stir in the carrots, tossing well to coat with the spice mixture, and cook until heated through, about 2 to 3 minutes', NULL, NULL, 8, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006611, 3000066, 11, 'Sprinkle with lemon juice and remove the bay leaf before serving.', NULL, NULL, 1, 0, NULL, '2025-04-12 08:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006701, 3000067, 1, 'STEP 1', 'https://www.themealdb.com/images/media/meals/cybyue1614349443.jpg', 'https://www.youtube.com/watch?v=tVpsZaejyYU', 9, 1, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006702, 3000067, 2, 'Cut the tenderloins into 5 equal-size pieces leaving the tail ends a little longer', NULL, NULL, 2, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006703, 3000067, 3, 'Take a clear plastic bag and slip one of the pieces in', NULL, NULL, 11, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006704, 3000067, 4, 'Bash it into an escalope the size of a side-plate with a rolling pin and repeat with the remaining pieces.', NULL, NULL, 7, 1, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006705, 3000067, 5, 'STEP 2', NULL, NULL, 5, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006706, 3000067, 6, 'Put the wine, paprika, some salt and pepper and the juice of ½ a lemon in a bowl and add the pork', NULL, NULL, 6, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006707, 3000067, 7, 'Leave to marinate for 20-30 minutes, while you get your barbecue to the stage where the coals are glowing but there are no flames.', NULL, NULL, 11, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006708, 3000067, 8, 'STEP 3', NULL, NULL, 18, 1, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006709, 3000067, 9, 'To make the chips, fill a basin with cool water and cut the potatoes into 3cm-thick chips', NULL, NULL, 13, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006710, 3000067, 10, 'Soak them in the water for 5 minutes and then change the water', NULL, NULL, 5, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006711, 3000067, 11, 'Leave for 5 more minutes', NULL, NULL, 8, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006712, 3000067, 12, 'Drain and then pat dry on a towel or with kitchen paper.', NULL, NULL, 3, 1, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006713, 3000067, 13, 'STEP 4', NULL, NULL, 6, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006714, 3000067, 14, 'Heat the oil in a deep fryer or a deep heavy-based pan with a lid to 130C and lower the chips into the oil (in batches)', NULL, NULL, 12, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006715, 3000067, 15, 'Blanch for 8-10 minutes', NULL, NULL, 1, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006716, 3000067, 16, 'Remove from the oil and drain well', NULL, NULL, 9, 1, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006717, 3000067, 17, 'Place on a tray to cool', NULL, NULL, 10, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006718, 3000067, 18, 'Reheat the oil to 180C (make sure it’s hot or your chips will be soggy) and lower the basket of chips into the oil (again, do this in batches)', NULL, NULL, 9, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006719, 3000067, 19, 'Leave to cook for 2 minutes and then give them a little shake', NULL, NULL, 4, 0, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006720, 3000067, 20, 'Cook for another minute or so until they are well coloured and crisp to the touch', NULL, NULL, 18, 1, NULL, '2025-08-12 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006801, 3000068, 1, 'Cut the lamb into large pieces.', 'https://www.themealdb.com/images/media/meals/ttfxxn1762773067.jpg', 'https://www.youtube.com/shorts/2mMT71Knp8E', 14, 1, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006802, 3000068, 2, 'Slice the cabbage into large wedges, keeping the core attached.', NULL, NULL, 6, 0, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006803, 3000068, 3, 'Add a layer of lamb pieces to the bottom of a large pot, fatty side down', NULL, NULL, 14, 0, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006804, 3000068, 4, 'Sprinkle with peppercorns and salt', NULL, NULL, 7, 1, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006805, 3000068, 5, 'Add a layer of cabbage wedges on top', NULL, NULL, 2, 0, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006806, 3000068, 6, 'Repeat with more layers of lamb, peppercorns, and cabbage, ending with cabbage on top.', NULL, NULL, 12, 0, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006807, 3000068, 7, 'Optional: Sprinkle a couple of tablespoons on top of the lamb for a thicker stew.', NULL, NULL, 9, 0, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006808, 3000068, 8, 'Add water to the pot and bring to a boil', NULL, NULL, 10, 1, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006809, 3000068, 9, 'Cover and reduce heat', NULL, NULL, 5, 0, NULL, '2025-07-07 11:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300006810, 3000068, 10, 'Cook on low heat for 2 – 3 hours, until the lamb gently falls away from the bone.', NULL, NULL, 15, 0, NULL, '2025-07-07 11:13:00.945');
