INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007410, 3000074, 10, 'Scatter over the clams, cover with the lid and steam for 2-4 mins, shaking the pan occasionally until the clams are open', NULL, NULL, 9, 0, NULL, '2025-07-30 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007411, 3000074, 11, 'Have a little taste before seasoning, as the clams can be quite salty', NULL, NULL, 9, 0, NULL, '2025-07-30 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007412, 3000074, 12, 'Then scatter over the chopped parsley', NULL, NULL, 2, 1, NULL, '2025-07-30 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007413, 3000074, 13, 'Eat with lots of crusty bread.', NULL, NULL, 9, 0, NULL, '2025-07-30 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007501, 3000075, 1, 'For the brioche buns heat the milk with the butter and molasses until the butter has melted', 'https://www.themealdb.com/images/media/meals/j80gmw1764372176.jpg', 'https://www.youtube.com/watch?v=tX3fN9AG_ik', 10, 1, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007502, 3000075, 2, 'Add the cold water and egg to this mix.', NULL, NULL, 11, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007503, 3000075, 3, 'In a large bowl place flour, salt and yeast and mix', NULL, NULL, 1, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007504, 3000075, 4, 'Then add the milk and water mix and stir with a wooden spoon until combined', NULL, NULL, 13, 1, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007505, 3000075, 5, 'You don''t have to knead the dough, it is perfectly fine to do this by hand with a wooden spoon, this doesn''t need to be very thorough', NULL, NULL, 5, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007506, 3000075, 6, 'Cover with a damp towel and stick in the fridge overnight.', NULL, NULL, 13, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007507, 3000075, 7, 'The next morning knead dough on a generously floured surface for a little and cut into eight equal pieces', NULL, NULL, 14, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007508, 3000075, 8, 'Shape these into balls and place on a baking sheet lined with parchment paper', NULL, NULL, 2, 1, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007509, 3000075, 9, 'Cover again with damp towel and let rise for about an hour or until double in size.', NULL, NULL, 1, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007510, 3000075, 10, 'Heat oven to 220 degrees Celsius', NULL, NULL, 10, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007511, 3000075, 11, 'Brush the buns with either milk, heavy cream or egg wash and sprinkle with sesame seeds, if desired', NULL, NULL, 9, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007512, 3000075, 12, 'Bake for about 15-20min or until golden', NULL, NULL, 5, 1, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007513, 3000075, 13, 'Let cool.', NULL, NULL, 6, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007514, 3000075, 14, 'For the toppings chop the onions and sauté in a bit of butter, let caramelize, this may take ten to 15 minutes, stir occasionally', NULL, NULL, 11, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007515, 3000075, 15, 'Rub the steaks with a bit of garlic and then grill or fry the steaks, the bacon, and eggs with salt and pepper, toast the buns after having cut in half', NULL, NULL, 9, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007516, 3000075, 16, 'Spread mustard on one bun half, layer each chivito with steak, a slice of ham, a slice of cheese, one bacon stripe, a tomato slice, and some lettuce', NULL, NULL, 10, 1, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007517, 3000075, 17, 'Place fried egg on top and sprinkle generously with chimichurri and some onions right before serving.', NULL, NULL, 8, 0, NULL, '2025-08-09 01:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007601, 3000076, 1, 'Get everything ready', 'https://www.themealdb.com/images/media/meals/yvpuuy1511797244.jpg', 'https://www.youtube.com/watch?v=qXPhVYpQLPA', 10, 1, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007602, 3000076, 2, 'Warm a 20cm (measured across the top) non-stick frying pan on a medium heat', NULL, NULL, 5, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007603, 3000076, 3, 'Crack the eggs into a bowl and beat them with a fork so they break up and mix, but not as completely as you would for scrambled egg', NULL, NULL, 5, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007604, 3000076, 4, 'With the heat on medium-hot, drop one knob of butter into the pan', NULL, NULL, 10, 1, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007605, 3000076, 5, 'It should bubble and sizzle, but not brown', NULL, NULL, 6, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007606, 3000076, 6, 'Season the eggs with the Parmesan and a little salt and pepper, and pour into the pan.', NULL, NULL, 9, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007607, 3000076, 7, 'Let the eggs bubble slightly for a couple of seconds, then take a wooden fork or spatula and gently draw the mixture in from the sides of the pan a few times, so it gathers in folds in the centre', NULL, NULL, 11, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007608, 3000076, 8, 'Leave for a few seconds, then stir again to lightly combine uncooked egg with cooked', NULL, NULL, 11, 1, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007609, 3000076, 9, 'Leave briefly again, and when partly cooked, stir a bit faster, stopping while there’s some barely cooked egg left', NULL, NULL, 6, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007610, 3000076, 10, 'With the pan flat on the heat, shake it back and forth a few times to settle the mixture', NULL, NULL, 1, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007611, 3000076, 11, 'It should slide easily in the pan and look soft and moist on top', NULL, NULL, 5, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007612, 3000076, 12, 'A quick burst of heat will brown the underside.', NULL, NULL, 3, 1, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007613, 3000076, 13, 'Grip the handle underneath', NULL, NULL, 6, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007614, 3000076, 14, 'Tilt the pan down away from you and let the omelette fall to the edge', NULL, NULL, 8, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007615, 3000076, 15, 'Fold the side nearest to you over by a third with your fork, and keep it rolling over, so the omelette tips onto a plate – or fold it in half, if that’s easier', NULL, NULL, 7, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007616, 3000076, 16, 'For a neat finish, cover the omelette with a piece of kitchen paper and plump it up a bit with your fingers', NULL, NULL, 9, 1, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007617, 3000076, 17, 'Rub the other knob of butter over to glaze', NULL, NULL, 11, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007618, 3000076, 18, 'Serve immediately.', NULL, NULL, 4, 0, NULL, '2025-05-03 18:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007701, 3000077, 1, 'oak the beans in water to cover overnight.Drain', 'https://www.themealdb.com/images/media/meals/n3xxd91598732796.jpg', 'https://www.youtube.com/watch?v=mulqW-J3Yy4', 8, 1, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007702, 3000077, 2, 'If skinless beans are unavailable, rub to loosen the skins, then discard the skins', NULL, NULL, 4, 0, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007703, 3000077, 3, 'Pat the beans dry with a towel.', NULL, NULL, 9, 0, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007704, 3000077, 4, 'Grind the beans in a food mill or meat grinder.If neither appliance is available, process them in a food processor but only until the beans form a paste', NULL, NULL, 7, 1, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007705, 3000077, 5, '(If blended too smoothly, the batter tends to fall apart during cooking.) Add the scallions, garlic, cilantro, cumin, baking powder, cayenne, salt, pepper, and coriander, if using', NULL, NULL, 6, 0, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007706, 3000077, 6, 'Refrigerate for at least 30 minutes.', NULL, NULL, 9, 0, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007707, 3000077, 7, 'Shape the bean mixture into 1-inch balls.Flatten slightly and coat with flour.', NULL, NULL, 7, 0, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007708, 3000077, 8, 'Heat at least 1½-inches of oil over medium heat to 365 degrees.', NULL, NULL, 7, 1, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007709, 3000077, 9, 'Fry the patties in batches, turning once, until golden brown on all sides, about 5 minutes.Remove with a wire mesh skimmer or slotted spoon', NULL, NULL, 6, 0, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007710, 3000077, 10, 'Serve as part of a meze or in pita bread with tomato-cucumber salad and tahina sauce.', NULL, NULL, 5, 0, NULL, '2025-04-17 00:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007801, 3000078, 1, 'Heat oil in a pan at medium heat', 'https://www.themealdb.com/images/media/meals/xquakq1619787532.jpg', 'https://www.youtube.com/watch?v=pOJEmDBgtSk', 10, 1, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007802, 3000078, 2, 'Then, add peanuts, dried chilies, dried shrimps and dhal', NULL, NULL, 3, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007803, 3000078, 3, 'Fry the aromatics until fragrant', NULL, NULL, 4, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007804, 3000078, 4, 'Remove from pan and leave aside.', NULL, NULL, 12, 1, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007805, 3000078, 5, 'Blend fried ingredients with tamarind paste and water until fine', NULL, NULL, 15, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007806, 3000078, 6, 'Then, sauté the blended ingredients in oil heated over low heat', NULL, NULL, 4, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007807, 3000078, 7, 'Continue cooking until the oil separates from the paste and turns a darker shade.', NULL, NULL, 16, 0, NULL, '2025-10-03 04:13:00.945');
