INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007810, 3000078, 10, 'Discard water.', NULL, NULL, 11, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007811, 3000078, 11, 'Slice onion and fried tofu, mince garlic, cut some cabbage and Chinese flowering cabbage (choi sam)', NULL, NULL, 8, 0, NULL, '2025-10-03 04:13:00.945');
