INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007813, 3000078, 13, 'Boil noodles to soften them if bought dried', NULL, NULL, 4, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007814, 3000078, 14, 'Also mix black soy sauce with water.', NULL, NULL, 2, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007815, 3000078, 15, 'To fry one portion of mee goreng mamak, heat oil and add 1/4 of the following ingredients in this order: garlic, onion, paste', NULL, NULL, 7, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007816, 3000078, 16, 'Sauté until fragrant', NULL, NULL, 3, 1, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007817, 3000078, 17, 'Optionally, add prawns.', NULL, NULL, 2, 0, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007818, 3000078, 18, 'Add in 1/4 amount of tofu, boiled potatoes, cabbage, Chinese flowering cabbage and prawn fritters', NULL, NULL, 7, 0, NULL, '2025-10-03 04:13:00.945');
