INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007820, 3000078, 20, 'Add noodles to the wok', NULL, NULL, 11, 1, NULL, '2025-10-03 04:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007901, 3000079, 1, 'To prepare the sauerkraut filling, melt the butter in a skillet over medium heat', 'https://www.themealdb.com/images/media/meals/45xxr21593348847.jpg', 'https://www.youtube.com/watch?v=lyqDmUroZrI', 12, 1, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007902, 3000079, 2, 'Stir in the onion, and cook until translucent, about 5 minutes', NULL, NULL, 4, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007903, 3000079, 3, 'Add the drained sauerkraut and cook for an additional 5 minutes', NULL, NULL, 11, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007904, 3000079, 4, 'Season to taste with salt and pepper, then remove to a plate to cool.', NULL, NULL, 2, 1, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007905, 3000079, 5, 'For the mashed potato filling, melt the butter in a skillet over medium heat', NULL, NULL, 6, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007906, 3000079, 6, 'Stir in the onion, and cook until translucent, about 5 minutes', NULL, NULL, 7, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007907, 3000079, 7, 'Stir into the mashed potatoes, and season with salt and white pepper.', NULL, NULL, 9, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007908, 3000079, 8, 'To make the dough, beat together the eggs and sour cream until smooth', NULL, NULL, 11, 1, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007909, 3000079, 9, 'Sift together the flour, salt, and baking powder; stir into the sour cream mixture until dough comes together', NULL, NULL, 6, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007910, 3000079, 10, 'Knead the dough on a lightly floured surface until firm and smooth', NULL, NULL, 8, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007911, 3000079, 11, 'Divide the dough in half, then roll out one half to 1/8 inch thickness', NULL, NULL, 12, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007912, 3000079, 12, 'Cut into 3 inch rounds using a biscuit cutter.', NULL, NULL, 3, 1, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007913, 3000079, 13, 'Place a small spoonful of the mashed potato filling into the center of each round', NULL, NULL, 2, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007914, 3000079, 14, 'Moisten the edges with water, fold over, and press together with a fork to seal', NULL, NULL, 6, 0, NULL, '2025-05-26 15:13:00.945');
INSERT INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES (300007915, 3000079, 15, 'Repeat procedure with the remaining dough and the sauerkraut filling.', NULL, NULL, 12, 0, NULL, '2025-05-26 15:13:00.945');
